package pkg

import (
	"context"
	"fmt"
	"sync"
)

type Registry struct {
	mu       sync.RWMutex
	runtimes map[RuntimeKind]Runtime
}

func NewRegistry(runtimes ...Runtime) *Registry {
	r := &Registry{runtimes: make(map[RuntimeKind]Runtime)}
	for _, rt := range runtimes {
		r.Register(rt)
	}
	return r
}

func (r *Registry) Register(rt Runtime) {
	if rt == nil {
		return
	}
	r.mu.Lock()
	defer r.mu.Unlock()
	r.runtimes[rt.Kind()] = rt
}

func (r *Registry) Runtime(kind RuntimeKind) (Runtime, bool) {
	r.mu.RLock()
	defer r.mu.RUnlock()
	rt, ok := r.runtimes[kind]
	return rt, ok
}

func (r *Registry) SpawnSession(ctx context.Context, input SessionInput) (Session, error) {
	rt, ok := r.Runtime(input.Runtime)
	if !ok {
		return nil, fmt.Errorf("runtime %q is not registered", input.Runtime)
	}
	return rt.SpawnSession(ctx, input)
}

func (r *Registry) DetectAll(ctx context.Context) []RuntimeInfo {
	r.mu.RLock()
	runtimes := make([]Runtime, 0, len(r.runtimes))
	for _, rt := range r.runtimes {
		runtimes = append(runtimes, rt)
	}
	r.mu.RUnlock()

	infos := make([]RuntimeInfo, 0, len(runtimes))
	for _, rt := range runtimes {
		info, err := rt.Detect(ctx)
		if err != nil {
			info = RuntimeInfo{
				Kind:       rt.Kind(),
				AuthStatus: AuthUnknown,
			}
		}
		infos = append(infos, info)
	}
	return infos
}

package tui

import (
	"context"
	"encoding/json"
	"fmt"
	"sort"
	"strings"
	"time"

	"github.com/charmbracelet/bubbles/key"
	"github.com/charmbracelet/bubbles/spinner"
	"github.com/charmbracelet/bubbles/textarea"
	"github.com/charmbracelet/bubbles/textinput"
	"github.com/charmbracelet/bubbles/viewport"
	tea "github.com/charmbracelet/bubbletea"
	"github.com/charmbracelet/glamour"
	"github.com/charmbracelet/glamour/ansi"
	"github.com/charmbracelet/glamour/styles"
	"github.com/charmbracelet/lipgloss"

	cula "github.com/git-hulk/cula/pkg"
)

type Config struct {
	DefaultWorkingDir string
	Registry          *cula.Registry
}

// spinnerThinking pulses a dot from small to large and back so the thinking
// indicator feels like a single icon breathing rather than a generic spinner.
var spinnerThinking = spinner.Spinner{
	Frames: []string{"⋅", "·", "•", "●", "•", "·"},
	FPS:    time.Second / 8,
}

var thinkingVerbs = []string{
	"Thinking", "Pondering", "Meandering", "Reasoning",
	"Reflecting", "Mulling", "Cogitating", "Ruminating",
	"Deliberating", "Considering",
}

type phase int

const (
	phaseLoading phase = iota
	phaseSelectRuntime
	phaseSelectModel
	phaseConfigure
	phaseChat
)

type blockKind int

const (
	blkUser blockKind = iota
	blkText
	blkToolCall
	blkCommand
	blkActivity
	blkNarration
	blkError
	blkInfo
)

type block struct {
	kind   blockKind
	title  string
	body   string
	active bool
	// timestamp marks when the block first appeared in the transcript. Only
	// rendered for user/assistant turns so the chat reads as a conversation
	// log without cluttering tool-call rows.
	timestamp time.Time
	// tool-call specific
	toolID     string
	toolName   string
	toolInput  map[string]any
	toolResult string
}

type eventMsg cula.Event
type eventsClosedMsg struct{}
type sessionReadyMsg struct {
	session cula.Session
}
type sessionErrMsg struct{ err error }
type runtimesDetectedMsg struct {
	infos []cula.RuntimeInfo
}

type Model struct {
	cfg Config

	phase phase

	// selection state
	runtimeInfos []cula.RuntimeInfo
	runtimeIdx   int

	selectedRuntime cula.RuntimeKind
	modelOpts       []cula.Model
	modelIdx        int
	selectedModel   string

	// configure phase
	workingDirInput textinput.Model
	sessionIDInput  textinput.Model
	configFocus     int

	// chat state
	workingDir string
	session    cula.Session
	eventsCh   <-chan cula.Event
	sessionID  string

	blocks   []block
	activity *block // transient activity slot — replaced by each new non-update activity, cleared by permanent events
	input    textarea.Model
	viewport viewport.Model
	spinner  spinner.Model

	busy          bool
	thinkingStart time.Time
	followOutput  bool
	state         cula.State
	width         int
	height        int
	err           string

	// markdown renderer for assistant text — recreated when bubble width
	// changes so word-wrap stays accurate.
	mdRenderer *glamour.TermRenderer
	mdWidth    int
}

func New(cfg Config) *Model {
	ta := textarea.New()
	ta.Placeholder = "Type a message and press Enter to send (Ctrl+J or Alt+Enter for newline)…"
	ta.Prompt = "│ "
	ta.CharLimit = 0
	ta.SetHeight(3)
	ta.ShowLineNumbers = false
	// Plain Enter is reserved for sending. Terminals do not reliably expose a
	// distinct Shift+Enter keypress, so use portable newline bindings instead.
	ta.KeyMap.InsertNewline = key.NewBinding(
		key.WithKeys("ctrl+j", "alt+enter"),
		key.WithHelp("ctrl+j/alt+enter", "insert newline"),
	)
	ta.Focus()

	sp := spinner.New()
	sp.Spinner = spinnerThinking
	sp.Style = styleSpinner

	vp := viewport.New(0, 0)
	vp.SetContent("")

	wdInput := textinput.New()
	wdInput.Placeholder = cfg.DefaultWorkingDir
	wdInput.SetValue(cfg.DefaultWorkingDir)
	wdInput.Prompt = "  "
	wdInput.CharLimit = 4096
	wdInput.Width = 60

	sidInput := textinput.New()
	sidInput.Placeholder = "leave blank to start a new session"
	sidInput.Prompt = "  "
	sidInput.CharLimit = 256
	sidInput.Width = 60

	return &Model{
		cfg:             cfg,
		phase:           phaseLoading,
		input:           ta,
		spinner:         sp,
		viewport:        vp,
		workingDirInput: wdInput,
		sessionIDInput:  sidInput,
		followOutput:    true,
	}
}

// SessionID returns the current session id, if any.
func (m *Model) SessionID() string {
	return m.sessionID
}

func (m *Model) Init() tea.Cmd {
	return tea.Batch(textarea.Blink, m.spinner.Tick, m.detectRuntimes())
}

func (m *Model) detectRuntimes() tea.Cmd {
	return func() tea.Msg {
		infos := m.cfg.Registry.DetectAll(context.Background())
		// stable order: claude-code, codex, opencode
		order := map[cula.RuntimeKind]int{
			cula.RuntimeClaudeCode: 0,
			cula.RuntimeCodex:      1,
			cula.RuntimeOpenCode:   2,
		}
		sort.Slice(infos, func(i, j int) bool {
			return order[infos[i].Kind] < order[infos[j].Kind]
		})
		return runtimesDetectedMsg{infos: infos}
	}
}

func (m *Model) spawnSession() tea.Cmd {
	return func() tea.Msg {
		ctx := context.Background()
		sess, err := m.cfg.Registry.SpawnSession(ctx, cula.SessionInput{
			Runtime:    m.selectedRuntime,
			Model:      m.selectedModel,
			SessionID:  m.sessionID,
			WorkingDir: m.workingDir,
		})
		if err != nil {
			return sessionErrMsg{err: err}
		}
		return sessionReadyMsg{session: sess}
	}
}

func waitForEvent(ch <-chan cula.Event) tea.Cmd {
	return func() tea.Msg {
		ev, ok := <-ch
		if !ok {
			return eventsClosedMsg{}
		}
		return eventMsg(ev)
	}
}

func (m *Model) Update(msg tea.Msg) (tea.Model, tea.Cmd) {
	switch msg := msg.(type) {
	case tea.WindowSizeMsg:
		m.width = msg.Width
		m.height = msg.Height
		m.layout()
		m.refreshTranscript()
		return m, nil

	case spinner.TickMsg:
		var cmd tea.Cmd
		m.spinner, cmd = m.spinner.Update(msg)
		// keep spinner ticking while loading or while busy
		if m.phase == phaseLoading || m.busy {
			if m.phase == phaseChat {
				m.refreshTranscript()
			}
			return m, cmd
		}
		return m, nil

	case runtimesDetectedMsg:
		m.runtimeInfos = msg.infos
		m.runtimeIdx = m.firstSelectableRuntime()
		m.phase = phaseSelectRuntime
		return m, nil

package tui

import (
	"github.com/charmbracelet/lipgloss"

	cula "github.com/git-hulk/cula/pkg"
)

// brand palette
//
// Neutrals carry a subtle violet undertone so they read as cohesive with the
// cula brand mark — pure greys feel sterile next to colored content. Hues are
// kept few on purpose: violet (brand), sky (user/info), emerald (assistant),
// amber (mutation/attention), red (error). Anything more would tip into
// rainbow vomit; the palette earns its color by giving each hue a job.
var (
	colBrand     = lipgloss.Color("#34d399") // violet — cula
	colBrandSoft = lipgloss.Color("#34d399") // dimmed violet for subtle borders
	colInk       = lipgloss.Color("#e5e3ee") // violet-tinted ink
	colInkSoft   = lipgloss.Color("#d3d0e0")
	colMuted     = lipgloss.Color("#a4a0b3")
	colFaint     = lipgloss.Color("#736f82")
	colDivider   = lipgloss.Color("#3a3450") // a touch lifted for separator visibility
	colUser      = lipgloss.Color("#60a5fa") // sky
	colAssistant = lipgloss.Color("#34d399") // emerald
	colAccent    = lipgloss.Color("#f59e0b") // amber — mutations / attention
	colInfo      = lipgloss.Color("#38bdf8") // cyan-sky — passive / informational
	colOk        = lipgloss.Color("#22c55e")
	colWarn      = lipgloss.Color("#f59e0b")
	colError     = lipgloss.Color("#ef4444")

	// colUserBubbleBg is a soft, lifted gray for the user message bubble —
	// slightly cooler than the terminal background so the prompt reads as one
	// grouped surface without competing with text colors.
	colUserBubbleBg = lipgloss.Color("#2a2733")
)

// glyphs — kept narrow so widths stay predictable across terminals.
const (
	glyphMark      = "◆"
	glyphCursor    = "▸"
	glyphRule      = "─"
	glyphDotActive = "●"
	glyphArrow     = "›"
)

var (
	styleBrandMark = lipgloss.NewStyle().
			Foreground(colBrand).
			Bold(true)

	styleSpinner = lipgloss.NewStyle().Foreground(colAccent)

	styleUserHeader = lipgloss.NewStyle().
			Foreground(colUser).
			Background(colUserBubbleBg).
			Bold(true)

	styleUserBody = lipgloss.NewStyle().
			Foreground(colInk).
			Background(colUserBubbleBg)

	styleUserBubble = lipgloss.NewStyle().
			Background(colUserBubbleBg).
			Padding(1, 1, 1, 1)

	styleUserMeta = lipgloss.NewStyle().
			Foreground(colMuted).
			Background(colUserBubbleBg)

	styleAssistantHeader = lipgloss.NewStyle().
				Foreground(colAssistant).
				Bold(true)

	styleAssistantBody = lipgloss.NewStyle().
				Foreground(colInkSoft)

	styleAssistantBubble = lipgloss.NewStyle().
				Padding(1, 1)

	styleAssistantMeta = lipgloss.NewStyle().
				Foreground(colMuted)

	// styleTool is for state-mutating tool calls (edit/write/exec/command) —
	// amber + bold so the eye lands on real changes when scanning.
	styleTool = lipgloss.NewStyle().
			Foreground(colAccent).
			Bold(true)

	// styleToolPassive is for read-only lookups (read/search/list/fetch) —
	// they recede in cool cyan so a long stretch of reads doesn't compete
	// with the mutation that actually mattered.
	styleToolPassive = lipgloss.NewStyle().
				Foreground(colInfo)

	styleToolBody = lipgloss.NewStyle().Foreground(colInk)

	styleError = lipgloss.NewStyle().
			Foreground(colError).
			Bold(true)

	styleFaint = lipgloss.NewStyle().Foreground(colFaint)

	// styleNarration renders codex-style commentary preamble — the "I'll do
	// X next" narration the agent emits between actions. Faint italic so it
	// reads as in-progress thinking rather than the terminal answer.
	styleNarration = lipgloss.NewStyle().
			Foreground(colMuted).
			Italic(true)

	styleHint = lipgloss.NewStyle().
			Foreground(colFaint).
			Italic(true).
			MarginTop(1)

	styleDivider = lipgloss.NewStyle().Foreground(colDivider)

	styleWelcomeCard = lipgloss.NewStyle().
				Foreground(colMuted).
				BorderStyle(lipgloss.RoundedBorder()).
				BorderForeground(colBrandSoft).
				Padding(1, 3).
				MarginTop(1)

	styleWelcomeTitle = lipgloss.NewStyle().
				Foreground(colBrand).
				Bold(true)

	// styleSessionInfo tints the session metadata block with a soft brand
	// violet so the "session" line reads as on-brand framing, not noise.
	styleSessionInfo = lipgloss.NewStyle().Foreground(colBrand)

	// styleStderrLabel marks stderr lines in cyan so they're distinguishable
	// from session info at a glance — different signal, different color.
	styleStderrLabel = lipgloss.NewStyle().Foreground(colInfo)
)

// runtimeTagline returns a short, factual descriptor for a runtime — used in
// selection screens to give each option a hint of identity beyond its name.
func runtimeTagline(kind cula.RuntimeKind) string {
	switch kind {
	case cula.RuntimeClaudeCode:
		return "Anthropic · claude-code CLI"
	case cula.RuntimeCodex:
		return "OpenAI · codex CLI"
	case cula.RuntimeOpenCode:
		return "open-source · opencode"
	}
	return ""
}

package runtime

import (
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"time"

	cula "github.com/git-hulk/cula/pkg"
)

var ErrSessionClosed = errors.New("session is closed")

func NormalizeInput(input cula.SessionInput) cula.SessionInput {
	if input.WorkingDir == "" {
		if wd, err := os.Getwd(); err == nil {
			input.WorkingDir = wd
		}
	}
	return input
}

func BinaryPath(cfg cula.Config, fallback string) string {
	if cfg.BinaryPath != "" {
		return cfg.BinaryPath
	}
	return fallback
}

func CommandEnv(input cula.SessionInput, cfg cula.Config) []string {
	env := os.Environ()
	env = append(env, cfg.Env...)
	env = append(env, input.Env...)
	return env
}

func Emit(events chan<- cula.Event, done <-chan struct{}, ev cula.Event) (ok bool) {
	defer func() {
		if recover() != nil {
			ok = false
		}
	}()
	if ev.Timestamp.IsZero() {
		ev.Timestamp = time.Now()
	}
	if done != nil {
		select {
		case <-done:
			return false
		default:
		}
	}
	if done == nil {
		events <- ev
		return true
	}
	select {
	case events <- ev:
		return true
	case <-done:
		return false
	}
}

func ExitCode(err error) int {
	if err == nil {
		return 0
	}
	var exitErr *exec.ExitError
	if errors.As(err, &exitErr) {
		return exitErr.ExitCode()
	}
	return 1
}

func LookupRuntime(binary, name string, kind cula.RuntimeKind, displayName string) cula.RuntimeInfo {
	info := cula.RuntimeInfo{
		Kind:       kind,
		Name:       displayName,
		AuthStatus: cula.AuthNotInstalled,
	}
	if binary == "" {
		binary = name
	}
	if path, err := exec.LookPath(binary); err == nil {
		info.Installed = true
		info.BinaryPath = path
		info.AuthStatus = cula.AuthUnknown
	} else if filepath.IsAbs(binary) {
		if st, statErr := os.Stat(binary); statErr == nil && !st.IsDir() {
			info.Installed = true
			info.BinaryPath = binary
			info.AuthStatus = cula.AuthUnknown
		}
	}
	return info
}

func Truncate(s string, n int) string {
	s = strings.TrimSpace(s)
	if n <= 0 || len(s) <= n {
		return s
	}
	return s[:n-3] + "..."
}

func StringMapSummary(input map[string]any) string {
	if len(input) == 0 {
		return ""
	}
	for _, key := range []string{"command", "cmd", "path", "file_path", "pattern", "query", "url"} {
		if v, ok := input[key]; ok {
			if s := fmt.Sprint(v); strings.TrimSpace(s) != "" {
				return Truncate(s, 80)
			}
		}
	}
	data, err := json.Marshal(input)
	if err != nil {
		return ""
	}
	return Truncate(string(data), 80)
}

func ParseArguments(args string) map[string]any {
	args = strings.TrimSpace(args)
	if args == "" {
		return nil
	}
	var input map[string]any
	if json.Unmarshal([]byte(args), &input) == nil {
		return input
	}
	return map[string]any{"arguments": args}
}

func WriteJSONLine(w io.Writer, v any) error {
	data, err := json.Marshal(v)
	if err != nil {
		return err
	}
	data = append(data, '\n')
	_, err = w.Write(data)
	return err
}

package runtime

import (
	"encoding/json"
	"strings"
)

type RawValue struct {
	raw json.RawMessage
}

func (r *RawValue) UnmarshalJSON(data []byte) error {
	r.raw = append(r.raw[:0], data...)
	return nil
}

func (r RawValue) Raw() json.RawMessage {
	return r.raw
}

func (r RawValue) AsString() (string, bool) {
	if len(r.raw) == 0 || r.raw[0] != '"' {
		return "", false
	}
	var s string
	if err := json.Unmarshal(r.raw, &s); err != nil {
		return "", false
	}
	return s, true
}

func (r RawValue) AsText() string {
	if s, ok := r.AsString(); ok {
		return s
	}
	var blocks []struct {
		Text string `json:"text"`
	}
	if len(r.raw) > 0 && r.raw[0] == '[' && json.Unmarshal(r.raw, &blocks) == nil {
		parts := make([]string, 0, len(blocks))
		for _, b := range blocks {
			if strings.TrimSpace(b.Text) != "" {
				parts = append(parts, b.Text)
			}
		}
		return strings.Join(parts, "\n")
	}
	return ""
}

