func (m *Model) firstSelectableRuntime() int {
	for i, info := range m.runtimeInfos {
		if info.Installed {
			return i
		}
	}
	return 0
}

func (m *Model) updateRuntimeSelect(msg tea.Msg) (tea.Model, tea.Cmd) {
	key, ok := msg.(tea.KeyMsg)
	if !ok {
		return m, nil
	}
	switch key.Type {
	case tea.KeyCtrlC, tea.KeyEsc:
		return m, tea.Quit
	case tea.KeyUp:
		m.moveRuntime(-1)
	case tea.KeyDown:
		m.moveRuntime(+1)
	case tea.KeyEnter:
		if len(m.runtimeInfos) == 0 {
			return m, nil
		}
		info := m.runtimeInfos[m.runtimeIdx]
		if !info.Installed {
			return m, nil
		}
		m.selectedRuntime = info.Kind
		m.modelOpts = info.Models
		m.modelIdx = 0
		m.phase = phaseSelectModel
	}
	switch key.String() {
	case "k":
		m.moveRuntime(-1)
	case "j":
		m.moveRuntime(+1)
	}
	return m, nil
}

func (m *Model) moveRuntime(delta int) {
	n := len(m.runtimeInfos)
	if n == 0 {
		return
	}
	idx := m.runtimeIdx
	for range n {
		idx = (idx + delta + n) % n
		if m.runtimeInfos[idx].Installed {
			m.runtimeIdx = idx
			return
		}
	}
}

func (m *Model) updateModelSelect(msg tea.Msg) (tea.Model, tea.Cmd) {
	key, ok := msg.(tea.KeyMsg)
	if !ok {
		return m, nil
	}
	total := len(m.modelOpts) + 1 // +1 for the "default" entry at index 0
	switch key.Type {
	case tea.KeyCtrlC, tea.KeyEsc:
		// go back to runtime selection
		m.phase = phaseSelectRuntime
		return m, nil
	case tea.KeyUp:
		m.modelIdx = (m.modelIdx - 1 + total) % total
	case tea.KeyDown:
		m.modelIdx = (m.modelIdx + 1) % total
	case tea.KeyEnter:
		if m.modelIdx == 0 {
			m.selectedModel = ""
		} else {
			m.selectedModel = m.modelOpts[m.modelIdx-1].ID
		}
		m.phase = phaseConfigure
		m.configFocus = 0
		m.workingDirInput.Focus()
		m.sessionIDInput.Blur()
		return m, textinput.Blink
	}
	switch key.String() {
	case "k":
		m.modelIdx = (m.modelIdx - 1 + total) % total
	case "j":
		m.modelIdx = (m.modelIdx + 1) % total
	}
	return m, nil
}

func (m *Model) updateConfigure(msg tea.Msg) (tea.Model, tea.Cmd) {
	if key, ok := msg.(tea.KeyMsg); ok {
		switch key.Type {
		case tea.KeyCtrlC:
			return m, tea.Quit
		case tea.KeyEsc:
			m.phase = phaseSelectModel
			m.workingDirInput.Blur()
			m.sessionIDInput.Blur()
			return m, nil
		case tea.KeyTab, tea.KeyShiftTab, tea.KeyDown, tea.KeyUp:
			m.toggleConfigFocus()
			return m, textinput.Blink
		case tea.KeyEnter:
			m.startChat()
			return m, m.spawnSession()
		}
	}

	var cmd tea.Cmd
	if m.configFocus == 0 {
		m.workingDirInput, cmd = m.workingDirInput.Update(msg)
	} else {
		m.sessionIDInput, cmd = m.sessionIDInput.Update(msg)
	}
	return m, cmd
}

func (m *Model) toggleConfigFocus() {
	if m.configFocus == 0 {
		m.configFocus = 1
		m.workingDirInput.Blur()
		m.sessionIDInput.Focus()
	} else {
		m.configFocus = 0
		m.sessionIDInput.Blur()
		m.workingDirInput.Focus()
	}
}

func (m *Model) startChat() {
	m.workingDir = strings.TrimSpace(m.workingDirInput.Value())
	if m.workingDir == "" {
		m.workingDir = m.cfg.DefaultWorkingDir
	}
	m.sessionID = strings.TrimSpace(m.sessionIDInput.Value())
	m.workingDirInput.Blur()
	m.sessionIDInput.Blur()
	m.phase = phaseChat
	m.followOutput = true
	m.layout()
	body := fmt.Sprintf("runtime=%s · model=%s · working directory=%s", m.selectedRuntime, valueOr(m.selectedModel, "default"), m.workingDir)
	if m.sessionID != "" {
		body += " · resume=" + m.sessionID
	}
	m.appendBlock(block{kind: blkInfo, title: "session", body: body})
	m.refreshTranscript()
}

func (m *Model) updateChat(msg tea.Msg) (tea.Model, tea.Cmd) {
	var cmds []tea.Cmd

	switch msg := msg.(type) {
	case sessionErrMsg:
		m.err = msg.err.Error()
		m.appendBlock(block{kind: blkError, title: "session error", body: msg.err.Error()})
		m.refreshTranscript()
		return m, nil

	case sessionReadyMsg:
		m.session = msg.session
		m.eventsCh = msg.session.Events()
		return m, waitForEvent(m.eventsCh)

	case eventMsg:
		m.handleEvent(cula.Event(msg))
		m.refreshTranscript()
		if m.eventsCh != nil {
			cmds = append(cmds, waitForEvent(m.eventsCh))
		}

	case eventsClosedMsg:
		m.busy = false
		m.thinkingStart = time.Time{}
		m.activity = nil
		m.dropTurnActivity()
		m.input.Focus()
		m.refreshTranscript()
		return m, nil

	case tea.KeyMsg:
		if m.handleHistoryKey(msg) {
			m.refreshTranscript()
			return m, nil
		}
		switch msg.Type {
		case tea.KeyCtrlC, tea.KeyEsc:
			if m.session != nil {
				_ = m.session.Cancel(context.Background())
			}
			return m, tea.Quit
		case tea.KeyEnter:
			if msg.Alt {
				break
			}
			if m.busy || m.session == nil {
				return m, nil
			}
			prompt := strings.TrimSpace(m.input.Value())
			if prompt == "" {
				return m, nil
			}
			m.input.Reset()
			m.input.Blur()
			m.activity = nil
			m.appendBlock(block{kind: blkUser, body: prompt, timestamp: time.Now()})
			m.busy = true
			m.thinkingStart = time.Now()
			m.refreshTranscript()
			cmds = append(cmds, m.sendPrompt(prompt), m.spinner.Tick)
			return m, tea.Batch(cmds...)
		case tea.KeyCtrlL:
			m.blocks = nil
			m.activity = nil
			m.followOutput = true
			m.refreshTranscript()
			return m, nil
		}
	}

	var cmd tea.Cmd
	// While the assistant is replying, drop key events targeted at the
	// textarea so the user can't type the next prompt until the turn
	// completes. Non-key messages (window resize, blink, etc.) still flow
	// through so the input stays correctly sized.
	if _, isKey := msg.(tea.KeyMsg); !isKey || !m.busy {
		m.input, cmd = m.input.Update(msg)
		cmds = append(cmds, cmd)
	}

	beforeOffset := m.viewport.YOffset
	m.viewport, cmd = m.viewport.Update(msg)
	if m.viewport.YOffset != beforeOffset {
		m.followOutput = m.viewport.AtBottom()
	}
	cmds = append(cmds, cmd)

	return m, tea.Batch(cmds...)
}

func (m *Model) handleHistoryKey(msg tea.KeyMsg) bool {
	switch msg.Type {
	case tea.KeyPgUp:
		m.viewport.PageUp()
		m.followOutput = false
		return true
	case tea.KeyPgDown:
		m.viewport.PageDown()
		m.followOutput = m.viewport.AtBottom()
		return true
	case tea.KeyHome:
		m.viewport.GotoTop()
		m.followOutput = false
		return true
	case tea.KeyEnd:
		m.viewport.GotoBottom()
		m.followOutput = true
		return true
	}

	switch msg.String() {
	case "ctrl+u":
		m.viewport.HalfPageUp()
		m.followOutput = false
		return true
	case "ctrl+d":
		m.viewport.HalfPageDown()
		m.followOutput = m.viewport.AtBottom()
		return true
	}

	return false
}

func (m *Model) sendPrompt(prompt string) tea.Cmd {
	return func() tea.Msg {
		if err := m.session.Send(context.Background(), prompt); err != nil {
			return sessionErrMsg{err: err}
		}
		return nil
	}
}

func (m *Model) handleEvent(ev cula.Event) {
	if ev.SessionID != "" {
		m.sessionID = ev.SessionID
	}

	switch ev.Type {
	case cula.EventState:
		m.state = ev.State
		switch ev.State {
		case cula.StateRunning:
		case cula.StateCompleted, cula.StateFailed, cula.StateCanceled:
			m.busy = false
			m.thinkingStart = time.Time{}
			m.activity = nil
			m.dropTurnActivity()
			m.input.Focus()
		}
	case cula.EventDone:
		m.busy = false
		m.thinkingStart = time.Time{}
		m.activity = nil
		m.dropTurnActivity()
		m.input.Focus()
	case cula.EventText:
		text := strings.TrimSpace(ev.Text)
		if text == "" {
			return
		}
		m.activity = nil
		m.dropThinkingBlocks()
		// Merge with the most recent assistant text block in this turn so
		// interleaved tool calls (edits/writes go to the permanent transcript)
		// don't split a single reply into multiple bubbles.
		for i := len(m.blocks) - 1; i >= 0; i-- {
			if m.blocks[i].kind == blkUser {
				break
			}
			if m.blocks[i].kind == blkText {
				m.blocks[i].body += "\n\n" + text
				return
			}
		}
		m.appendBlock(block{kind: blkText, body: text, timestamp: time.Now()})
	case cula.EventActivity:
		if ev.Activity == nil {
			return
		}
		switch ev.Activity.Type {
		case cula.ActivityThinking:
			// Coalesce: at most one "Thinking…" row per turn, and never one
			// after assistant text has already landed in the turn. Repeated
			// reasoning bursts would otherwise stack into a wall of bullets,
			// or — once we've dropped the live row to make room for text —
			// reappear below the reply with a second activity banner.
			if m.shouldSuppressThinking() {
				return
			}
			m.activity = nil

			m.appendBlock(block{kind: blkActivity, title: thinkingTitle})
		case cula.ActivityCommand:
			m.activity = &block{kind: blkCommand, title: "command", body: strings.Join(ev.Activity.Parameters, "  •  "), active: true}
		case cula.ActivityToolCall:
			m.activity = &block{kind: blkToolCall, title: "tool", body: strings.Join(ev.Activity.Parameters, " "), active: true}
		case cula.ActivityNarration:
			body := strings.TrimSpace(strings.Join(ev.Activity.Parameters, "\n"))
			if body == "" {
				return
			}
			m.activity = nil
			m.appendBlock(block{kind: blkNarration, body: body})
		}
	case cula.EventToolCall:
		if ev.ToolCall == nil {
			return
		}
		m.activity = nil
		m.appendBlock(block{
			kind:      blkToolCall,
			title:     ev.ToolCall.Name,
			toolID:    ev.ToolCall.ID,
			toolName:  ev.ToolCall.Name,
			toolInput: ev.ToolCall.Input,
			active:    true,
		})
	case cula.EventToolResult:
		if ev.ToolResult == nil {
			return
		}
		for i := len(m.blocks) - 1; i >= 0; i-- {
			b := &m.blocks[i]
			if b.kind == blkToolCall && b.toolID == ev.ToolResult.ToolCallID {
				b.toolResult = ev.ToolResult.Content
				b.active = false
				return
			}
		}
		if m.activity != nil && m.activity.kind == blkToolCall && m.activity.toolID == ev.ToolResult.ToolCallID {
			m.activity.toolResult = ev.ToolResult.Content
			m.activity.active = false
		}
	case cula.EventError:
		m.activity = nil
		m.appendBlock(block{kind: blkError, title: "error", body: ev.Error})
	case cula.EventStderr:
		m.appendBlock(block{kind: blkInfo, title: "stderr", body: ev.Error})
	}
}

func (m *Model) appendBlock(b block) {
	m.blocks = append(m.blocks, b)
}

// dropThinkingBlocks strips Thinking… activity rows from the transcript once a
// turn has completed. They're useful as a live indicator while the assistant
// is mid-reply, but afterwards they only add noise above the actual answer.
func (m *Model) dropThinkingBlocks() {
	out := m.blocks[:0]
	for _, b := range m.blocks {
		if b.kind == blkActivity && b.title == thinkingTitle {
			continue
		}
		out = append(out, b)
	}
	m.blocks = out
}

// dropTurnActivity strips every activity-kind row (Thinking, tool calls,
// commands) from the transcript at turn end. While the assistant is working
// these rows are a useful live progress indicator, but once the final answer
// has landed they're just noise above the reply.
func (m *Model) dropTurnActivity() {
	out := m.blocks[:0]
	for _, b := range m.blocks {
		if isActivityBlock(b.kind) {
			continue
		}
		out = append(out, b)
	}
	m.blocks = out
}

const thinkingTitle = "Thinking…"

// shouldSuppressThinking reports whether a new "Thinking…" row should be
// dropped on arrival. We suppress when this turn already has a Thinking… row
// (coalesce repeated bursts) or any assistant text (codex emits reasoning
// items between agentMessage chunks; a second Thinking… below the reply just
// duplicates the busy footer).
func (m *Model) shouldSuppressThinking() bool {
	for i := len(m.blocks) - 1; i >= 0; i-- {
		b := m.blocks[i]
		if b.kind == blkUser {
			return false
		}
		if b.kind == blkText {
			return true
		}
		if b.kind == blkActivity && b.title == thinkingTitle {
			return true
		}
	}
	return false
}

func (m *Model) layout() {
	if m.width == 0 || m.height == 0 {
		return
	}
	inputHeight := 5
	vpHeight := max(m.height-inputHeight-2, 3)
	m.viewport.Width = m.width
	m.viewport.Height = vpHeight
	m.input.SetWidth(m.width - 2)
}

func (m *Model) View() string {
	switch m.phase {
	case phaseLoading:
		return m.renderLoading()
	case phaseSelectRuntime:
		return m.renderRuntimeSelect()
	case phaseSelectModel:
		return m.renderModelSelect()
	case phaseConfigure:
		return m.renderConfigure()
	case phaseChat:
		return m.renderChat()
	}
	return ""
}

func (m *Model) renderConfigure() string {
	var b strings.Builder
	b.WriteString(renderWordmark())
	b.WriteString("  ")
	summary := "runtime: " + string(m.selectedRuntime)
	if m.selectedModel != "" {
		summary += " · model: " + m.selectedModel
	}
	b.WriteString(styleFaint.Render(summary + " · session settings"))
	b.WriteString("\n\n")

	wdLabel := "  working dir"
	sidLabel := "  session id"
	if m.configFocus == 0 {
		wdLabel = styleAssistantHeader.Render("▸ working dir")
	} else {
		sidLabel = styleAssistantHeader.Render("▸ session id")
	}

	b.WriteString(wdLabel + " " + styleFaint.Render("(optional, defaults to current dir)") + "\n")
	b.WriteString(m.workingDirInput.View() + "\n\n")
	b.WriteString(sidLabel + " " + styleFaint.Render("(optional, leave blank for a new session)") + "\n")
	b.WriteString(m.sessionIDInput.View() + "\n\n")
	b.WriteString(styleHint.Render("Tab switch field · Enter start · Esc back · Ctrl+C quit"))
	return b.String()
}

func (m *Model) renderLoading() string {
	return renderWordmark() + "\n" +
		styleFaint.Render("  "+greeting()+" — an agent runtime sandbox") + "\n\n" +
		m.spinner.View() + " " + styleFaint.Render("scanning for installed runtimes…")
}

func (m *Model) renderRuntimeSelect() string {
	var b strings.Builder
	b.WriteString(renderWordmark())
	b.WriteString("  ")
	b.WriteString(styleFaint.Render("pick a runtime"))
	b.WriteString("\n\n")

	for i, info := range m.runtimeInfos {
		b.WriteString(m.renderRuntimeOption(info, i == m.runtimeIdx))
		b.WriteString("\n")
	}
	b.WriteString("\n")
	b.WriteString(styleHint.Render("↑/↓ navigate · Enter select · Esc quit"))
	return b.String()
}

func (m *Model) renderRuntimeOption(info cula.RuntimeInfo, selected bool) string {
	cursor := "  "
	if selected {
		cursor = styleAssistantHeader.Render(glyphCursor + " ")
	}

	name := string(info.Kind)
	authBadge := renderAuthBadge(info)
	tagline := runtimeTagline(info.Kind)

	if !info.Installed {
		line := cursor + styleFaint.Render(name+"  not installed")
		if tagline != "" {
			line += styleFaint.Render("  · " + tagline)
		}
		return line
	}

	version := ""
	if info.Version != "" {
		version = styleFaint.Render(" v" + info.Version)
	}

	nameStyle := lipgloss.NewStyle()
	if selected {
		nameStyle = nameStyle.Bold(true)
	}
	line := cursor + nameStyle.Render(name) + version + "  " + authBadge
	if tagline != "" {
		line += "\n  " + styleFaint.Render("    "+tagline)
	}
	return line
}

func renderAuthBadge(info cula.RuntimeInfo) string {
	switch info.AuthStatus {
	case cula.AuthLoggedIn:
		return lipgloss.NewStyle().Foreground(colOk).Render(glyphDotActive + " logged in")
	case cula.AuthLoggedOut:
		return lipgloss.NewStyle().Foreground(colWarn).Render(glyphDotActive + " logged out")
	case cula.AuthNotInstalled:
		return styleFaint.Render(glyphDotActive + " not installed")
	}
	return styleFaint.Render(glyphDotActive + " unknown")
}

func (m *Model) renderModelSelect() string {
	var b strings.Builder
	b.WriteString(renderWordmark())
	b.WriteString("  ")
	b.WriteString(styleFaint.Render("runtime: ") + string(m.selectedRuntime) + styleFaint.Render(" · pick a model"))
	b.WriteString("\n\n")

	options := []string{"(default)"}
	for _, mo := range m.modelOpts {
		label := mo.ID
		if mo.Name != "" && mo.Name != mo.ID {
			label = mo.Name + "  " + styleFaint.Render(mo.ID)
		}
		options = append(options, label)
	}

	for i, opt := range options {
		cursor := "  "
		style := lipgloss.NewStyle()
		if i == m.modelIdx {
			cursor = styleAssistantHeader.Render(glyphCursor + " ")
			style = lipgloss.NewStyle().Bold(true)
		}
		if i == 0 {
			b.WriteString(cursor + style.Render(opt) + " " + styleFaint.Render("— let the runtime pick"))
		} else {
			b.WriteString(cursor + style.Render(opt))
		}
		b.WriteString("\n")
	}
	b.WriteString("\n")
	b.WriteString(styleHint.Render("↑/↓ navigate · Enter select · Esc back"))
	return b.String()
}

func (m *Model) renderChat() string {
	body := m.viewport.View()
	footer := m.renderFooter()
	return lipgloss.JoinVertical(lipgloss.Left, body, footer)
}

func (m *Model) renderFooter() string {
	rule := ""
	if m.width > 0 {
		rule = styleDivider.Render(strings.Repeat(glyphRule, m.width))
	}
	status := styleFaint.Render(m.historyStatus())
	hintStyled := styleHint.Render("PgUp/PgDn scroll · Ctrl+U/Ctrl+D half-page · Home top · End latest · Enter send · Ctrl+J/Alt+Enter newline · Ctrl+L clear · Esc/Ctrl+C quit")
	return lipgloss.JoinVertical(lipgloss.Left, rule, status, m.input.View(), hintStyled)
}

// renderThinkingHint renders the live thinking status line shown directly under
// the Thinking… activity row. The assistant banner is already rendered above
// the activity section, so this line focuses on progress only.
func (m *Model) renderThinkingHint() string {
	icon := m.spinner.View()
	if m.thinkingStart.IsZero() {
		return styleHint.Render(fmt.Sprintf("%s %s… (input locked until reply)", icon, thinkingVerbs[0]))
	}
	elapsed := time.Since(m.thinkingStart)
	secs := int(elapsed.Seconds())
	verb := thinkingVerbs[(secs/5)%len(thinkingVerbs)]
	return styleHint.Render(fmt.Sprintf("%s %s… (%ds · input locked until reply)\n", icon, verb, secs))
}

func (m *Model) refreshTranscript() {
	if m.phase != phaseChat || m.viewport.Height == 0 {
		return
	}
	oldOffset := m.viewport.YOffset
	follow := m.followOutput || m.viewport.AtBottom()
	var sb strings.Builder
	if len(m.blocks) == 0 && m.activity == nil {
		sb.WriteString(m.renderWelcome())
		m.viewport.SetContent(sb.String())
		m.viewport.GotoTop()
		return
	}
	// Activity-kind blocks (thinking, tool calls, commands) cluster under a
	// single assistant banner so a long stretch of operations reads as one
	// turn rather than a wall of separator-divided rows. Assistant text
	// bubbles are transparent to the grouping — only a fresh user prompt
	// closes the banner, so tool calls split by mid-turn prose stay visually
	// under the same speaker.
	visible := m.visibleBlocks()
	inActivityGroup := false
	for _, b := range visible {
		current := isActivityBlock(b.kind)
		if current && !inActivityGroup {
			sb.WriteString(m.renderActivityBanner())
			inActivityGroup = true
		}
		if b.kind == blkUser {
			inActivityGroup = false
		}
		sb.WriteString(m.renderBlock(b))
		sb.WriteString("\n")
	}
	if m.activity != nil {
		if !inActivityGroup {
			sb.WriteString(m.renderActivityBanner())
		}
		sb.WriteString(m.renderBlock(*m.activity))
		sb.WriteString("\n")
	}
	m.viewport.SetContent(sb.String())
	if follow {
		m.viewport.GotoBottom()
		m.followOutput = true
		return
	}
	m.viewport.SetYOffset(oldOffset)
	m.followOutput = m.viewport.AtBottom()
}

func isActivityBlock(k blockKind) bool {
	return k == blkActivity || k == blkToolCall || k == blkCommand || k == blkNarration
}

// visibleBlocks returns the transcript with older tool calls of the same name
// dropped within each turn. A turn is everything between user prompts; within
// it, only the latest tool call of each toolName survives so a long run of
// Read/Grep operations collapses to one row each.
func (m *Model) visibleBlocks() []block {
	if len(m.blocks) == 0 {
		return nil
	}
	out := make([]block, 0, len(m.blocks))
	turnStart := 0
	flush := func(end int) {
		latest := make(map[string]int)
		for k := turnStart; k < end; k++ {

			if m.blocks[k].kind == blkToolCall {
				latest[m.blocks[k].toolName] = k
			}
		}
		for k := turnStart; k < end; k++ {
			b := m.blocks[k]
			if b.kind == blkToolCall && latest[b.toolName] != k {
				continue
			}
			out = append(out, b)
		}
	}
	for i, b := range m.blocks {
		if b.kind == blkUser {
			flush(i)
			out = append(out, b)
			turnStart = i + 1
		}
	}
	flush(len(m.blocks))
	return out
}

func (m *Model) renderActivityBanner() string {
	style := lipgloss.NewStyle().Foreground(colAssistant).Bold(true)
	return style.Render("▎ "+m.assistantDisplayName()) + "\n"
}

func (m *Model) renderWelcome() string {
	title := styleWelcomeTitle.Render(glyphMark + " ready when you are")
	body := styleFaint.Render("type a prompt below and press Enter") + "\n" +
		styleFaint.Render("Ctrl+L clears the transcript · Esc cancels")
	card := styleWelcomeCard.Render(title + "\n\n" + body)
	if m.width > 8 {
		card = lipgloss.PlaceHorizontal(m.width-2, lipgloss.Center, card)
	}
	return "\n" + card + "\n"
}

func (m *Model) historyStatus() string {
	if len(m.viewport.View()) == 0 {
		return "history: empty"
	}
	if m.viewport.AtBottom() {
		return "history: live tail"
	}
	return fmt.Sprintf("history: %.0f%%", m.viewport.ScrollPercent()*100)
}

func (m *Model) renderBlock(b block) string {
	switch b.kind {
	case blkUser:
		header := styleUserHeader.Render("▎ you") + styleUserMeta.Render(formatStamp(b.timestamp))
		return m.renderBubble(styleUserBubble, header, styleUserBody.Render("\n"+b.body))
	case blkText:
		header := styleAssistantHeader.Render("▎ "+m.assistantDisplayName()) + styleAssistantMeta.Render(formatStamp(b.timestamp))
		body := m.renderMarkdown(b.body)
		return m.renderBubble(styleAssistantBubble, header, "\n"+body)
	case blkCommand:
		return "  " + styleTool.Render(activityBullet(b.active && m.busy)+" $ ") + styleToolBody.Render(b.body)
	case blkActivity:
		if b.title == thinkingTitle && m.busy {
			return "  " + m.renderThinkingHint()
		}
		return "  " + styleFaint.Render(activityBullet(false)+" "+b.title)
	case blkNarration:
		// Indent each line under the activity banner so a multi-paragraph
		// commentary chunk reads as one quoted aside instead of bleeding
		// out to the bubble's edge.
		lines := strings.Split(b.body, "\n")
		for i, ln := range lines {
			lines[i] = "  " + styleFaint.Render(glyphArrow+" ") + styleNarration.Render(ln)
		}
		return strings.Join(lines, "\n")
	case blkToolCall:
		bullet := activityBullet(b.active && m.busy)
		style := toolHeaderStyle(b.toolName)
		head := "  " + style.Render(bullet+" "+b.toolName)
		if args := formatToolArgs(b.toolName, b.toolInput); args != "" {
			head += styleToolBody.Render("(" + truncate(args, 120) + ")")
		}
		if summary := summarizeToolResult(b); summary != "" {
			head += "\n     " + styleFaint.Render("⎿  "+summary)
		}
		return head
	case blkError:
		return styleError.Render("✗ "+valueOr(b.title, "error")+": ") + b.body
	case blkInfo:
		switch b.title {
		case "session":
			return styleSessionInfo.Render("• session ") + styleFaint.Render(b.body)
		case "stderr":
			return styleStderrLabel.Render("• stderr ") + styleFaint.Render(b.body)
		}
		return styleFaint.Render("• " + b.title + ": " + b.body)
	}
	return b.body
}

// activityBullet returns the leading glyph for an activity row: a sparkle
// while the row is the current in-flight action, a filled bullet once it has
// settled. Mirrors the Claude Code transcript style.
func activityBullet(active bool) string {
	if active {
		return "✳"
	}
	return "⏺"
}

// formatToolArgs returns the inside of the `Tool(...)` parens for a tool
// call header. Promotes the primary param value when there is one (file_path,
// command, etc.); otherwise joins the remaining inputs as `k=v, k=v`.
func formatToolArgs(name string, input map[string]any) string {
	if len(input) == 0 {
		return ""
	}
	if key := primaryInputKey(name); key != "" {
		if v, ok := input[key]; ok {
			return stringifyDetail(v)
		}
	}
	keys := make([]string, 0, len(input))
	for k := range input {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	parts := make([]string, 0, len(keys))
	for _, k := range keys {
		parts = append(parts, k+"="+stringifyArg(input[k]))
	}
	return strings.Join(parts, ", ")
}

// summarizeToolResult returns the `⎿` continuation text for a finished tool
// call: the first non-empty line of the tool result, truncated. Returns "" for
// in-flight calls or empty results so we don't render a dangling continuation.
func summarizeToolResult(b block) string {
	if b.active {
		return ""
	}
	for ln := range strings.SplitSeq(b.toolResult, "\n") {
		ln = strings.TrimSpace(ln)
		if ln != "" {
			return truncate(ln, 120)
		}
	}
	return ""
}

func primaryInputKey(name string) string {
	switch strings.ToLower(name) {
	case "bash", "shell", "exec", "run":
		return "command"
	case "read", "view", "open", "cat", "file_read",
		"edit", "write", "multiedit", "multi_edit",
		"notebookedit", "notebook_edit", "apply_patch":
		return "file_path"
	case "ls", "list", "tree":
		return "path"
	case "grep", "search", "ripgrep", "rg", "find":
		return "pattern"
	case "websearch", "web_search":
		return "query"
	case "fetch", "webfetch", "web_fetch", "curl", "http":
		return "url"
	case "task", "agent", "subagent":
		return "description"
	}
	return ""
}

func stringifyDetail(v any) string {
	switch t := v.(type) {
	case string:
		return truncate(t, 200)
	case nil:
		return "null"
	}
	b, err := json.Marshal(v)
	if err != nil {
		return fmt.Sprintf("%v", v)
	}
	return truncate(string(b), 200)
}

func stringifyArg(v any) string {
	switch t := v.(type) {
	case string:
		return truncate(t, 60)
	case nil:
		return "null"
	}
	b, err := json.Marshal(v)
	if err != nil {
		return fmt.Sprintf("%v", v)
	}
	return truncate(string(b), 60)
}

func truncate(s string, max int) string {
	if len(s) <= max {
		return s
	}
	if max <= 1 {
		return "…"
	}
	return s[:max-1] + "…"
}

func valueOr(s, fallback string) string {
	if s == "" {
		return fallback
	}
	return s
}

func (m *Model) assistantDisplayName() string {
	runtimeName := string(m.selectedRuntime)
	var modelName string
	for _, info := range m.runtimeInfos {
		if info.Kind != m.selectedRuntime {
			continue
		}
		if info.Name != "" {
			runtimeName = info.Name
		}
		for _, mdl := range info.Models {
			if mdl.ID == m.selectedModel {
				modelName = mdl.Name
				break
			}
		}
		break
	}
	if modelName == "" {
		modelName = m.selectedModel
	}
	modelName = shortModelName(runtimeName, modelName)
	if modelName == "" {
		return runtimeName
	}
	return runtimeName + "(" + modelName + ")"
}

// shortModelName drops a leading runtime brand from the model label so the
// header reads "Claude Code(Opus 4.7)" instead of "Claude Code(Claude Opus 4.7)".
func shortModelName(runtime, model string) string {
	for _, prefix := range brandPrefixes(runtime) {
		if rest, ok := strings.CutPrefix(model, prefix); ok {
			return rest
		}
	}
	return model
}

func brandPrefixes(runtime string) []string {
	first := strings.SplitN(runtime, " ", 2)[0]
	if first == "" {
		return nil
	}
	return []string{first + " "}
}

// renderWordmark prints the cula brand mark for full-page screens.
func renderWordmark() string {
	return styleBrandMark.Render(glyphMark+" cula") + styleFaint.Render(" "+glyphArrow)
}

// greeting returns a soft, time-aware salutation for the loading screen.
func greeting() string {
	h := time.Now().Hour()
	switch {
	case h < 5:
		return "still up?"
	case h < 12:
		return "good morning"
	case h < 17:
		return "good afternoon"
	case h < 22:
		return "good evening"
	default:
		return "burning the midnight oil"
	}
}

// formatStamp renders a block's local-time stamp as " · 15:04" — a leading
// dot separator keeps it visually attached to the speaker label. Returns ""
// for the zero time so legacy/system blocks stay untimestamped.
func formatStamp(t time.Time) string {
	if t.IsZero() {
		return ""
	}
	return "  " + t.Format("15:04")
}

// renderMarkdown renders assistant text through glamour so headings, lists,
// code blocks, and inline emphasis get proper terminal styling. Falls back to
// the raw body if the renderer can't be built or the input fails to render —
// we never want a markdown error to swallow the reply.
func (m *Model) renderMarkdown(body string) string {
	body = strings.TrimRight(body, "\n")
	width := max(m.viewport.Width-4, 20)
	if m.mdRenderer == nil || m.mdWidth != width {
		r, err := glamour.NewTermRenderer(
			glamour.WithStyles(assistantBubbleMarkdownStyle()),
			glamour.WithWordWrap(width),
		)
		if err != nil {
			return styleAssistantBody.Render(body)
		}
		m.mdRenderer = r
		m.mdWidth = width
	}
	out, err := m.mdRenderer.Render(body)
	if err != nil {
		return styleAssistantBody.Render(body)
	}
	return strings.Trim(out, "\n")
}

// assistantBubbleMarkdownStyle returns a glamour style derived from the dark
// theme but stripped of internal margins and embedded background colors so the
// assistant bubble paints as a single unbroken surface. Without this, glamour's
// per-element backgrounds (H1, inline code, code blocks) and document margin
// punch holes in the bubble's bg fill.
func assistantBubbleMarkdownStyle() ansi.StyleConfig {
	cfg := styles.DarkStyleConfig
	zero := uint(0)
	cfg.Document.Margin = &zero
	cfg.Document.BlockPrefix = ""
	cfg.Document.BlockSuffix = ""
	cfg.H1.BackgroundColor = nil
	cfg.Code.BackgroundColor = nil
	cfg.CodeBlock.Margin = &zero
	if cfg.CodeBlock.Chroma != nil {
		cfg.CodeBlock.Chroma.Error.BackgroundColor = nil
	}
	return cfg
}

package codex

import (
	"encoding/json"
	"fmt"
	"strings"

	iruntime "github.com/git-hulk/cula/internal/runtime"
	cula "github.com/git-hulk/cula/pkg"
)

type eventParser struct{}

func ParseEvent(raw json.RawMessage) (cula.Event, bool) {
	return eventParser{}.parse(raw)
}

type event struct {
	Method string `json:"method"`
	Params params `json:"params"`
}

type params struct {
	Item *item `json:"item"`
	Turn *turn `json:"turn"`
}

type turn struct {
	Status string `json:"status"`
}

type item struct {
	ID        string         `json:"id"`
	Type      string         `json:"type"`
	Name      string         `json:"name"`
	Text      string         `json:"text"`
	Phase     string         `json:"phase"`
	Command   string         `json:"command"`
	ExitCode  *float64       `json:"exitCode"`
	Arguments string         `json:"arguments"`
	Input     map[string]any `json:"input"`
	Metadata  map[string]any `json:"metadata"`
}

func (p eventParser) parse(raw json.RawMessage) (cula.Event, bool) {
	var ev event
	if json.Unmarshal(raw, &ev) != nil || ev.Method == "" {
		return cula.Event{}, false
	}
	switch ev.Method {
	case "turn/completed":
		if ev.Params.Turn == nil || ev.Params.Turn.Status == "" {
			return cula.Event{}, false
		}
		return cula.Event{Type: cula.EventDone}, true
	case "item/started":
		if ev.Params.Item != nil {
			return p.itemEvent(ev.Params.Item, false)
		}
	case "item/completed":
		if ev.Params.Item != nil {
			return p.completedItemEvent(ev.Params.Item)
		}
	}
	return cula.Event{}, false
}

func (p eventParser) completedItemEvent(item *item) (cula.Event, bool) {
	if item.Type == "agentMessage" && strings.TrimSpace(item.Text) != "" {
		// Codex tags mid-turn preamble/progress narration as "commentary"
		// and the terminal reply as "final_answer". Surface commentary as
		// an activity narration row so it groups under the assistant
		// banner and gets cleared at turn end alongside other progress
		// indicators, instead of stacking inside the final answer bubble.
		if item.Phase == "commentary" {
			return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityNarration, Parameters: []string{item.Text}}}, true
		}
		return cula.Event{Type: cula.EventText, Text: item.Text}, true
	}
	return p.itemEvent(item, true)
}

func (eventParser) itemEvent(item *item, completed bool) (cula.Event, bool) {
	switch item.Type {
	case "reasoning":
		if completed {
			return cula.Event{}, false
		}
		return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityThinking}}, true
	case "functionCall", "tool_call":
		input := item.Input
		if input == nil {
			input = iruntime.ParseArguments(item.Arguments)
		}
		if !completed {
			return cula.Event{Type: cula.EventToolCall, ToolCall: &cula.ToolCall{ID: item.ID, Name: item.Name, Input: input}}, true
		}
		return cula.Event{}, false
	case "commandExecution":
		params := []string{}
		if item.Command != "" {
			params = append(params, iruntime.Truncate(item.Command, 160))
		}
		if completed && item.ExitCode != nil {
			params = append(params, fmt.Sprintf("%d", int(*item.ExitCode)))
		}
		return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityCommand, Parameters: params}}, true
	}
	return cula.Event{}, false
}

package codex

import (
	"context"
	"encoding/json"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"

	iruntime "github.com/git-hulk/cula/internal/runtime"
	cula "github.com/git-hulk/cula/pkg"
)

type Runtime struct {
	cfg cula.Config
}

func New(cfg cula.Config) *Runtime {
	return &Runtime{cfg: cfg}
}

func (r *Runtime) Kind() cula.RuntimeKind {
	return cula.RuntimeCodex
}

func (r *Runtime) Detect(ctx context.Context) (cula.RuntimeInfo, error) {
	binary := iruntime.BinaryPath(r.cfg, "codex")
	info := iruntime.LookupRuntime(binary, "codex", cula.RuntimeCodex, "Codex CLI")
	if !info.Installed {
		return info, nil
	}
	if out, err := exec.CommandContext(ctx, binary, "--version").Output(); err == nil {
		re := regexp.MustCompile(`codex-cli\s+(\S+)`)
		if m := re.FindStringSubmatch(string(out)); len(m) > 1 {
			info.Version = m[1]
		}
	}
	home, _ := os.UserHomeDir()
	if data, err := os.ReadFile(filepath.Join(home, ".codex", "auth.json")); err == nil {
		var auth struct {
			Tokens struct {
				AccessToken string `json:"access_token"`
			} `json:"tokens"`
		}
		if json.Unmarshal(data, &auth) == nil && auth.Tokens.AccessToken != "" {
			info.AuthStatus = cula.AuthLoggedIn
		} else {
			info.AuthStatus = cula.AuthLoggedOut
		}
	} else {
		info.AuthStatus = cula.AuthLoggedOut
	}
	if data, err := os.ReadFile(filepath.Join(home, ".codex", "models_cache.json")); err == nil {
		var cache struct {
			Models []struct {
				Slug        string `json:"slug"`
				DisplayName string `json:"display_name"`
			} `json:"models"`
		}
		if json.Unmarshal(data, &cache) == nil {
			for _, m := range cache.Models {
				info.Models = append(info.Models, cula.Model{ID: m.Slug, Name: m.DisplayName})
			}
		}
	}
	return info, nil
}

func (r *Runtime) SpawnSession(ctx context.Context, input cula.SessionInput) (cula.Session, error) {
	return newSession(ctx, r, input)
}

package codex

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os/exec"
	"sync"
	"sync/atomic"
	"syscall"

	iruntime "github.com/git-hulk/cula/internal/runtime"
	cula "github.com/git-hulk/cula/pkg"
)

type session struct {
	input cula.SessionInput

	cmd   *exec.Cmd
	stdin io.WriteCloser

	events chan cula.Event

	cancelCtx context.CancelFunc
	promptCh  chan string
	doneCh    chan struct{}
	doneOnce  sync.Once
	wg        sync.WaitGroup
	nextID    atomic.Int64
	threadID  string
	mu        sync.Mutex
	sessionID string
	state     cula.State
}

var _ cula.Session = (*session)(nil)

func newSession(ctx context.Context, rt *Runtime, input cula.SessionInput) (cula.Session, error) {
	input = iruntime.NormalizeInput(input)
	runCtx, cancel := context.WithCancel(context.Background())
	cmd := exec.CommandContext(runCtx, iruntime.BinaryPath(rt.cfg, "codex"), "app-server", "--listen", "stdio://")
	cmd.Dir = input.WorkingDir
	cmd.Env = iruntime.CommandEnv(input, rt.cfg)

	stdin, err := cmd.StdinPipe()
	if err != nil {
		cancel()
		return nil, err
	}
	stdout, err := cmd.StdoutPipe()
	if err != nil {
		cancel()
		return nil, err
	}
	stderr, err := cmd.StderrPipe()
	if err != nil {
		cancel()
		return nil, err
	}
	if err := cmd.Start(); err != nil {
		cancel()
		return nil, err
	}

	s := &session{
		input:     input,
		cmd:       cmd,
		stdin:     stdin,
		events:    make(chan cula.Event, 1024),
		cancelCtx: cancel,
		promptCh:  make(chan string, 16),
		doneCh:    make(chan struct{}),
		sessionID: input.SessionID,
		state:     cula.StateRunning,
	}
	iruntime.Emit(s.events, s.doneCh, cula.Event{Type: cula.EventState, Runtime: cula.RuntimeCodex, SessionID: input.SessionID, State: cula.StateRunning})
	if err := s.start(ctx, stdout, stderr); err != nil {
		_ = cmd.Process.Kill()
		cancel()
		return nil, err
	}
	return s, nil
}

func (s *session) start(ctx context.Context, stdout io.Reader, stderr io.Reader) error {
	scanner := bufio.NewScanner(stdout)
	scanner.Buffer(make([]byte, 0, 64*1024), 10*1024*1024)
	if err := s.initialize(scanner); err != nil {
		return err
	}

	s.wg.Add(2)
	go func() {
		defer s.wg.Done()
		s.readStdout(scanner)
	}()
	go func() {
		defer s.wg.Done()
		s.readStderr(stderr)
	}()
	go s.wait()
	go s.consumePrompts()

	if s.input.Prompt != "" {
		if err := s.Send(ctx, s.input.Prompt); err != nil {
			_ = s.Cancel(ctx)
			return err
		}
	}
	return nil
}

func (s *session) Send(ctx context.Context, prompt string) error {
	if prompt == "" {
		return nil
	}
	select {
	case s.promptCh <- prompt:
		return nil
	case <-s.doneCh:
		return iruntime.ErrSessionClosed
	case <-ctx.Done():
		return ctx.Err()
	}
}

func (s *session) Events() <-chan cula.Event {
	return s.events
}

func (s *session) Cancel(ctx context.Context) error {
	s.doneOnce.Do(func() {
		s.mu.Lock()
		s.state = cula.StateCanceled
		s.mu.Unlock()
		iruntime.Emit(s.events, nil, cula.Event{Type: cula.EventState, Runtime: cula.RuntimeCodex, SessionID: s.sessionID, State: cula.StateCanceled})
		close(s.doneCh)
		s.cancelCtx()
		if s.cmd != nil && s.cmd.Process != nil {
			_ = s.cmd.Process.Signal(syscall.SIGTERM)
		}
	})
	return nil
}

func (s *session) nextRequestID() int64 {
	return s.nextID.Add(1)
}

func (s *session) initialize(scanner *bufio.Scanner) error {
	initID := s.nextRequestID()
	if err := iruntime.WriteJSONLine(s.stdin, map[string]any{
		"jsonrpc": "2.0",
		"id":      initID,
		"method":  "initialize",
		"params": map[string]any{
			"clientInfo": map[string]string{"name": "cula", "version": "0.1.0"},
		},
	}); err != nil {
		return fmt.Errorf("send initialize: %w", err)
	}
	if _, err := s.readJSONRPCResponse(scanner, initID, false); err != nil {
		return fmt.Errorf("initialize: %w", err)
	}
	if err := iruntime.WriteJSONLine(s.stdin, map[string]any{
		"jsonrpc": "2.0",
		"method":  "initialized",
	}); err != nil {
		return fmt.Errorf("send initialized: %w", err)
	}

	threadID := s.nextRequestID()
	params := map[string]any{
		"cwd":            s.input.WorkingDir,
		"approvalPolicy": string(s.input.Permission),
		"sandbox":        string(s.input.Sandbox),
	}
	if params["approvalPolicy"] == "" {
		params["approvalPolicy"] = "never"
	}
	if params["sandbox"] == "" {
		params["sandbox"] = "danger-full-access"
	}
	if s.input.Model != "" {
		params["model"] = s.input.Model
	}
	if err := iruntime.WriteJSONLine(s.stdin, map[string]any{
		"jsonrpc": "2.0",
		"id":      threadID,
		"method":  "thread/start",
		"params":  params,
	}); err != nil {
		return fmt.Errorf("send thread/start: %w", err)
	}
	result, err := s.readJSONRPCResponse(scanner, threadID, true)
	if err != nil {
		return fmt.Errorf("thread/start: %w", err)
	}
	var resp struct {
		Thread struct {
			ID string `json:"id"`
		} `json:"thread"`
	}
	if err := json.Unmarshal(result, &resp); err != nil {
		return fmt.Errorf("parse thread/start: %w", err)
	}
	if resp.Thread.ID == "" {
		return fmt.Errorf("thread/start returned empty thread id")
	}
	s.threadID = resp.Thread.ID
	s.sessionID = resp.Thread.ID
	return nil
}

func (s *session) consumePrompts() {
	for {
		select {
		case <-s.doneCh:
			return
		case prompt := <-s.promptCh:
			turnID := s.nextRequestID()
			req := map[string]any{
				"jsonrpc": "2.0",
				"id":      turnID,
				"method":  "turn/start",
				"params": map[string]any{
					"threadId": s.threadID,
					"input": []map[string]string{
						{"type": "text", "text": prompt},
					},
				},
			}
			if err := iruntime.WriteJSONLine(s.stdin, req); err != nil {
				iruntime.Emit(s.events, s.doneCh, cula.Event{
					Type:      cula.EventError,
					Runtime:   cula.RuntimeCodex,
					SessionID: s.sessionID,
					Error:     fmt.Sprintf("send turn/start: %v", err),
				})
			}
		}
	}
}

func (s *session) readStdout(scanner *bufio.Scanner) {
	for scanner.Scan() {
		line := append([]byte(nil), scanner.Bytes()...)
		var raw json.RawMessage
		if err := json.Unmarshal(line, &raw); err != nil {
			iruntime.Emit(s.events, s.doneCh, cula.Event{Type: cula.EventError, Runtime: cula.RuntimeCodex, SessionID: s.sessionID, Error: fmt.Sprintf("decode stdout: %v", err)})
			continue
		}
		ev, ok := ParseEvent(raw)
		if !ok {
			ev = cula.Event{Type: cula.EventRaw}
		}
		s.emitEvent(raw, ev)
	}
	if err := scanner.Err(); err != nil {
		iruntime.Emit(s.events, s.doneCh, cula.Event{Type: cula.EventError, Runtime: cula.RuntimeCodex, SessionID: s.sessionID, Error: fmt.Sprintf("read stdout: %v", err)})
	}
}

func (s *session) readStderr(r io.Reader) {
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 64*1024), 10*1024*1024)
	for scanner.Scan() {
		iruntime.Emit(s.events, s.doneCh, cula.Event{
			Type:      cula.EventStderr,
			Runtime:   cula.RuntimeCodex,
			SessionID: s.sessionID,
			Error:     scanner.Text(),
		})
	}
	if err := scanner.Err(); err != nil {
		iruntime.Emit(s.events, s.doneCh, cula.Event{
			Type:      cula.EventError,
			Runtime:   cula.RuntimeCodex,
			SessionID: s.sessionID,
			Error:     fmt.Sprintf("read stderr: %v", err),
		})
	}
}

func (s *session) readJSONRPCResponse(scanner *bufio.Scanner, requestID int64, forward bool) (json.RawMessage, error) {
	for scanner.Scan() {
		line := append([]byte(nil), scanner.Bytes()...)
		var msg struct {
			ID     *json.RawMessage `json:"id"`
			Result json.RawMessage  `json:"result"`
			Error  *struct {
				Code    int    `json:"code"`
				Message string `json:"message"`
			} `json:"error"`
			Method string `json:"method"`
		}
		if err := json.Unmarshal(line, &msg); err != nil {
			continue
		}
		if msg.ID != nil {
			var id int64
			if json.Unmarshal(*msg.ID, &id) == nil && id == requestID {
				if msg.Error != nil {
					return nil, fmt.Errorf("JSON-RPC error %d: %s", msg.Error.Code, msg.Error.Message)
				}
				return msg.Result, nil
			}
		}
		if forward {
			var raw json.RawMessage
			if json.Unmarshal(line, &raw) == nil {
				ev, ok := ParseEvent(raw)
				if !ok {
					ev = cula.Event{Type: cula.EventRaw}
				}
				s.emitEvent(raw, ev)
			}
		}

	}
	if err := scanner.Err(); err != nil {
		return nil, err
	}
	return nil, fmt.Errorf("stdout closed before response %d", requestID)
}

func (s *session) emitEvent(raw json.RawMessage, ev cula.Event) {
	ev.Runtime = cula.RuntimeCodex
	ev.SessionID = s.sessionID
	ev.Raw = raw
	iruntime.Emit(s.events, s.doneCh, ev)
}

func (s *session) wait() {
	err := s.cmd.Wait()
	s.wg.Wait()
	code := iruntime.ExitCode(err)
	s.mu.Lock()
	canceled := s.state == cula.StateCanceled
	s.mu.Unlock()
	if !canceled {
		state := cula.StateCompleted
		if code != 0 {
			state = cula.StateFailed
		}
		s.mu.Lock()
		s.state = state
		s.mu.Unlock()
		iruntime.Emit(s.events, nil, cula.Event{
			Type:      cula.EventState,
			Runtime:   cula.RuntimeCodex,
			SessionID: s.sessionID,
			State:     state,
			ExitCode:  &code,
		})
	}
	s.doneOnce.Do(func() {
		close(s.doneCh)
	})
	close(s.events)
}

package claudecode

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os/exec"
	"sync"
	"syscall"

	iruntime "github.com/git-hulk/cula/internal/runtime"
	cula "github.com/git-hulk/cula/pkg"
)

var _ cula.Session = (*session)(nil)

type session struct {
	mu        sync.Mutex
	runtime   *Runtime
	input     cula.SessionInput
	events    chan cula.Event
	sessionID string
	childCmd  *exec.Cmd
	promptCh  chan string
	doneCh    chan struct{}
	doneOnce  sync.Once
	ctx       context.Context
	cancelCtx context.CancelFunc
	parser    eventParser
}

func newSession(ctx context.Context, rt *Runtime, input cula.SessionInput) (cula.Session, error) {
	input = iruntime.NormalizeInput(input)
	runCtx, cancel := context.WithCancel(context.Background())
	s := &session{
		runtime:   rt,
		input:     input,
		events:    make(chan cula.Event, 1024),
		sessionID: input.SessionID,
		promptCh:  make(chan string, 16),
		doneCh:    make(chan struct{}),
		ctx:       runCtx,
		cancelCtx: cancel,
		parser:    eventParser{},
	}
	iruntime.Emit(s.events, s.doneCh, cula.Event{
		Type:      cula.EventState,
		Runtime:   cula.RuntimeClaudeCode,
		SessionID: input.SessionID,
		State:     cula.StateRunning,
	})
	go s.consumePrompts()
	if input.Prompt != "" {
		if err := s.Send(ctx, input.Prompt); err != nil {
			_ = s.Cancel(ctx)
			return nil, err
		}
	}
	return s, nil
}

func (s *session) Send(ctx context.Context, prompt string) error {
	if prompt == "" {
		return nil
	}
	select {
	case s.promptCh <- prompt:
		return nil
	case <-s.doneCh:
		return iruntime.ErrSessionClosed
	case <-ctx.Done():
		return ctx.Err()
	}
}

func (s *session) Events() <-chan cula.Event {
	return s.events
}

func (s *session) Cancel(ctx context.Context) error {
	s.doneOnce.Do(func() {
		exit := -1
		iruntime.Emit(s.events, nil, cula.Event{
			Type:      cula.EventState,
			Runtime:   cula.RuntimeClaudeCode,
			SessionID: s.sessionID,
			State:     cula.StateCanceled,
			ExitCode:  &exit,
		})

		close(s.doneCh)
		s.cancelCtx()
		s.mu.Lock()
		cmd := s.childCmd
		s.mu.Unlock()
		if cmd != nil && cmd.Process != nil {
			_ = cmd.Process.Signal(syscall.SIGTERM)
		}
		close(s.events)
	})
	return nil
}

func (s *session) consumePrompts() {
	for {
		select {
		case prompt := <-s.promptCh:
			exitCode := s.spawnAndWait(prompt)
			if exitCode != 0 {
				exit := exitCode
				iruntime.Emit(s.events, s.doneCh, cula.Event{
					Type:      cula.EventState,
					Runtime:   cula.RuntimeClaudeCode,
					SessionID: s.sessionID,
					State:     cula.StateFailed,
					ExitCode:  &exit,
				})
			}
		case <-s.doneCh:
			return
		}
	}
}

func (s *session) spawnAndWait(prompt string) int {
	args := s.buildArgs(s.sessionID, prompt)
	cmd := exec.CommandContext(s.ctx, iruntime.BinaryPath(s.runtime.cfg, "claude"), args...)
	cmd.Dir = s.input.WorkingDir
	cmd.Env = iruntime.CommandEnv(s.input, s.runtime.cfg)

	stdout, err := cmd.StdoutPipe()
	if err != nil {
		s.emitError(fmt.Sprintf("stdout pipe: %v", err))
		return 1
	}
	stderr, err := cmd.StderrPipe()
	if err != nil {
		s.emitError(fmt.Sprintf("stderr pipe: %v", err))
		return 1
	}
	if err := cmd.Start(); err != nil {
		s.emitError(fmt.Sprintf("start claude-code: %v", err))
		return 1
	}

	s.mu.Lock()
	s.childCmd = cmd
	s.mu.Unlock()

	var wg sync.WaitGroup
	wg.Add(2)
	go func() {
		defer wg.Done()
		s.readStdout(stdout)
	}()
	go func() {
		defer wg.Done()
		s.readStderr(stderr)
	}()

	waitErr := cmd.Wait()
	wg.Wait()

	s.mu.Lock()
	s.childCmd = nil
	s.mu.Unlock()

	exitCode := iruntime.ExitCode(waitErr)
	if exitCode == 0 {
		iruntime.Emit(s.events, s.doneCh, cula.Event{
			Type:      cula.EventDone,
			Runtime:   cula.RuntimeClaudeCode,
			SessionID: s.sessionID,
		})
	}
	return exitCode
}

func (s *session) buildArgs(sessionID, prompt string) []string {
	args := []string{"-p", "--output-format", "stream-json", "--verbose"}
	if s.input.Permission != cula.PermissionNever {
		args = append(args, "--dangerously-skip-permissions")
	}
	if s.input.Model != "" {
		args = append(args, "--model", s.input.Model)
	}
	if sessionID != "" {
		args = append(args, "--resume", sessionID)
	}
	return append(args, prompt)
}

func (s *session) readStdout(r io.Reader) {
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 64*1024), 10*1024*1024)
	for scanner.Scan() {
		line := append([]byte(nil), scanner.Bytes()...)
		var raw json.RawMessage
		if err := json.Unmarshal(line, &raw); err != nil {
			s.emitError(fmt.Sprintf("decode stdout: %v", err))
			continue
		}
		if id := s.parser.captureSession(raw); id != "" {
			s.sessionID = id
		}
		ev, ok := ParseEvent(raw)
		if !ok {
			ev = cula.Event{Type: cula.EventRaw}
		}
		s.emitEvent(raw, ev)
	}
	if err := scanner.Err(); err != nil {
		s.emitError(fmt.Sprintf("read stdout: %v", err))
	}
}

func (s *session) readStderr(r io.Reader) {
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 64*1024), 10*1024*1024)
	for scanner.Scan() {
		iruntime.Emit(s.events, s.doneCh, cula.Event{
			Type:      cula.EventStderr,
			Runtime:   cula.RuntimeClaudeCode,
			SessionID: s.sessionID,
			Error:     scanner.Text(),
		})
	}
	if err := scanner.Err(); err != nil {
		s.emitError(fmt.Sprintf("read stderr: %v", err))
	}
}

func (s *session) emitEvent(raw json.RawMessage, ev cula.Event) {
	ev.Runtime = cula.RuntimeClaudeCode
	ev.SessionID = s.sessionID
	ev.Raw = raw
	iruntime.Emit(s.events, s.doneCh, ev)
}

func (s *session) emitError(message string) {
	iruntime.Emit(s.events, s.doneCh, cula.Event{
		Type:      cula.EventError,
		Runtime:   cula.RuntimeClaudeCode,
		SessionID: s.sessionID,
		Error:     message,
	})
}

package claudecode

import (
	"context"
	"encoding/json"
	"os/exec"
	"regexp"
	"strings"

	iruntime "github.com/git-hulk/cula/internal/runtime"
	cula "github.com/git-hulk/cula/pkg"
)

type Runtime struct {
	cfg cula.Config
}

func New(cfg cula.Config) *Runtime {
	return &Runtime{cfg: cfg}
}

func (r *Runtime) Kind() cula.RuntimeKind {
	return cula.RuntimeClaudeCode
}

func (r *Runtime) Detect(ctx context.Context) (cula.RuntimeInfo, error) {
	binary := iruntime.BinaryPath(r.cfg, "claude")
	info := iruntime.LookupRuntime(binary, "claude", cula.RuntimeClaudeCode, "Claude Code")
	if !info.Installed {
		return info, nil
	}
	if out, err := exec.CommandContext(ctx, binary, "--version").Output(); err == nil {
		re := regexp.MustCompile(`(\d+\.\d+\.\d+)`)
		if m := re.FindStringSubmatch(string(out)); len(m) > 1 {
			info.Version = m[1]
		}
	}
	if out, err := exec.CommandContext(ctx, binary, "auth", "status").Output(); err == nil {
		var status struct {
			LoggedIn bool `json:"loggedIn"`
		}
		if json.Unmarshal([]byte(strings.TrimSpace(string(out))), &status) == nil && status.LoggedIn {
			info.AuthStatus = cula.AuthLoggedIn
		} else {
			info.AuthStatus = cula.AuthLoggedOut
		}
	} else {
		info.AuthStatus = cula.AuthLoggedOut
	}
	info.Models = []cula.Model{
		{ID: "claude-opus-4-7", Name: "Claude Opus 4.7"},
		{ID: "claude-opus-4-6", Name: "Claude Opus 4.6"},
		{ID: "claude-sonnet-4-6", Name: "Claude Sonnet 4.6"},
		{ID: "claude-haiku-4-5", Name: "Claude Haiku 4.5"},
	}
	return info, nil
}

func (r *Runtime) SpawnSession(ctx context.Context, input cula.SessionInput) (cula.Session, error) {
	return newSession(ctx, r, input)
}

package claudecode

import (
	"encoding/json"
	"strings"

	iruntime "github.com/git-hulk/cula/internal/runtime"
	cula "github.com/git-hulk/cula/pkg"
)

type eventParser struct{}

func ParseEvent(raw json.RawMessage) (cula.Event, bool) {
	return eventParser{}.parse(raw)
}

type event struct {
	Type      string            `json:"type"`
	SubType   string            `json:"subtype"`
	Role      string            `json:"role"`
	SessionID string            `json:"session_id"`
	Message   *message          `json:"message"`
	Content   iruntime.RawValue `json:"content"`
}

type message struct {
	Content []block `json:"content"`
}

type block struct {
	Type      string            `json:"type"`
	ID        string            `json:"id"`
	Name      string            `json:"name"`
	Text      string            `json:"text"`
	Input     map[string]any    `json:"input"`
	ToolUseID string            `json:"tool_use_id"`
	Content   iruntime.RawValue `json:"content"`
}

func (eventParser) captureSession(raw json.RawMessage) string {
	var ev struct {
		Type      string `json:"type"`
		SubType   string `json:"subtype"`
		SessionID string `json:"session_id"`
	}
	if json.Unmarshal(raw, &ev) == nil && ev.SessionID != "" &&
		(ev.Type == "init" || (ev.Type == "system" && ev.SubType == "init")) {
		return ev.SessionID
	}
	return ""
}

func (p eventParser) parse(raw json.RawMessage) (cula.Event, bool) {
	var ev event
	if json.Unmarshal(raw, &ev) != nil {
		return cula.Event{}, false
	}
	switch ev.Type {
	case "result":
		return cula.Event{Type: cula.EventDone}, true
	case "assistant":
		if out, ok := p.assistantEvent(ev); ok {
			return out, true
		}
	case "user":
		if out, ok := p.toolResultEvent(ev); ok {
			return out, true
		}
	}
	if ev.Role == "assistant" {
		if text, ok := ev.Content.AsString(); ok && strings.TrimSpace(text) != "" {
			return cula.Event{Type: cula.EventText, Text: text}, true
		}
	}
	for _, b := range contentBlocks(ev.Content) {
		if out, ok := toolResultBlockEvent(b); ok {
			return out, true
		}
	}
	return cula.Event{}, false
}

func (eventParser) assistantEvent(ev event) (cula.Event, bool) {
	if ev.Message == nil {
		return cula.Event{}, false
	}
	for _, b := range ev.Message.Content {
		switch b.Type {
		case "thinking":
			return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityThinking}}, true
		case "tool_use":
			return cula.Event{Type: cula.EventToolCall, ToolCall: &cula.ToolCall{ID: b.ID, Name: b.Name, Input: b.Input}}, true
		}
	}
	for _, b := range ev.Message.Content {
		if b.Type == "text" && strings.TrimSpace(b.Text) != "" {
			return cula.Event{Type: cula.EventText, Text: b.Text}, true
		}
	}
	return cula.Event{}, false
}

func (eventParser) toolResultEvent(ev event) (cula.Event, bool) {
	if ev.Message == nil {
		return cula.Event{}, false
	}
	for _, b := range ev.Message.Content {
		if out, ok := toolResultBlockEvent(b); ok {
			return out, true
		}
	}
	return cula.Event{}, false
}

func toolResultBlockEvent(b block) (cula.Event, bool) {
	if b.Type != "tool_result" || b.ToolUseID == "" {
		return cula.Event{}, false
	}
	text := b.Content.AsText()
	if text == "" {
		return cula.Event{}, false
	}
	return cula.Event{Type: cula.EventToolResult, ToolResult: &cula.ToolResult{ToolCallID: b.ToolUseID, Content: text}}, true
}

func contentBlocks(content iruntime.RawValue) []block {
	if raw := content.Raw(); len(raw) == 0 || raw[0] != '[' {
		return nil
	}
	var blocks []block
	_ = json.Unmarshal(content.Raw(), &blocks)
	return blocks
}

package opencode

import (
	"context"
	"os"
	"os/exec"
	"path/filepath"
	"regexp"
	"strings"

	iruntime "github.com/git-hulk/cula/internal/runtime"
	cula "github.com/git-hulk/cula/pkg"
)

type Runtime struct {
	cfg cula.Config
}

func New(cfg cula.Config) *Runtime {
	return &Runtime{cfg: cfg}
}

func (r *Runtime) Kind() cula.RuntimeKind {
	return cula.RuntimeOpenCode
}

func (r *Runtime) Detect(ctx context.Context) (cula.RuntimeInfo, error) {
	binary := iruntime.BinaryPath(r.cfg, "opencode")
	info := iruntime.LookupRuntime(binary, "opencode", cula.RuntimeOpenCode, "OpenCode")
	if !info.Installed {
		return info, nil
	}
	if out, err := exec.CommandContext(ctx, binary, "--version").Output(); err == nil {
		re := regexp.MustCompile(`(\d+\.\d+\.\d+)`)
		if m := re.FindStringSubmatch(string(out)); len(m) > 1 {
			info.Version = m[1]
		}
	}
	home, _ := os.UserHomeDir()
	authPath := filepath.Join(home, ".local", "share", "opencode", "auth.json")
	if data, err := os.ReadFile(authPath); err == nil && len(data) > 2 {
		info.AuthStatus = cula.AuthLoggedIn
	} else {
		info.AuthStatus = cula.AuthLoggedOut
	}
	if out, err := exec.CommandContext(ctx, binary, "models").Output(); err == nil {
		for _, line := range strings.Split(string(out), "\n") {
			id := strings.TrimSpace(line)
			if id != "" && strings.Contains(id, "/") {
				info.Models = append(info.Models, cula.Model{ID: id, Name: id})
			}
		}
	}
	return info, nil
}

func (r *Runtime) SpawnSession(ctx context.Context, input cula.SessionInput) (cula.Session, error) {
	return newSession(ctx, r, input)
}

package opencode

import (
	"encoding/json"

	cula "github.com/git-hulk/cula/pkg"
)

type eventParser struct{}

func ParseEvent(raw json.RawMessage) (cula.Event, bool) {
	return eventParser{}.parse(raw)
}

type event struct {
	Type      string `json:"type"`
	SessionID string `json:"sessionID"`
	Part      *part  `json:"part"`
}

type part struct {
	ID       string         `json:"id"`
	Type     string         `json:"type"`
	Text     string         `json:"text"`
	Reason   string         `json:"reason"`
	Tool     string         `json:"tool"`
	CallID   string         `json:"callID"`
	Input    map[string]any `json:"input"`
	State    *state         `json:"state"`
	Metadata map[string]any `json:"metadata"`
}

type state struct {
	Status string         `json:"status"`
	Title  string         `json:"title"`
	Input  map[string]any `json:"input"`
	Output string         `json:"output"`
	Error  string         `json:"error"`
}

func (eventParser) captureSession(raw json.RawMessage) string {
	var ev struct {
		SessionID string `json:"sessionID"`
	}
	if json.Unmarshal(raw, &ev) == nil {
		return ev.SessionID
	}
	return ""
}

func (p eventParser) parse(raw json.RawMessage) (cula.Event, bool) {
	var ev event
	if json.Unmarshal(raw, &ev) != nil {
		return cula.Event{}, false
	}
	if ev.Type == "step_finish" {
		return p.stepFinishEvent(ev)
	}
	if ev.Part == nil {
		return cula.Event{}, false
	}
	switch ev.Part.Type {
	case "text":
		if ev.Part.Text != "" {
			return cula.Event{Type: cula.EventText, Text: ev.Part.Text}, true
		}
	case "reasoning":
		return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityThinking}}, true
	case "tool":
		return p.toolEvent(ev.Part)
	}
	return cula.Event{}, false
}

func (eventParser) stepFinishEvent(ev event) (cula.Event, bool) {
	if ev.Part == nil {
		return cula.Event{Type: cula.EventDone}, true
	}
	switch ev.Part.Reason {
	case "", "stop", "length", "error":
		return cula.Event{Type: cula.EventDone}, true
	default:
		return cula.Event{}, false
	}
}

func (eventParser) toolEvent(part *part) (cula.Event, bool) {
	toolName := part.Tool
	if toolName == "" && part.State != nil {
		toolName = part.State.Title
	}
	input := part.Input
	if input == nil && part.State != nil {
		input = part.State.Input
	}
	if part.State != nil && (part.State.Status == "completed" || part.State.Status == "error") {
		content := part.State.Output
		if content == "" {
			content = part.State.Error
		}
		if content != "" {
			return cula.Event{Type: cula.EventToolResult, ToolResult: &cula.ToolResult{ToolCallID: part.CallID, Content: content}}, true
		}
	}
	return cula.Event{Type: cula.EventToolCall, ToolCall: &cula.ToolCall{ID: part.CallID, Name: toolName, Input: input}}, true
}

package opencode

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os/exec"
	"sync"
	"syscall"

	iruntime "github.com/git-hulk/cula/internal/runtime"
	cula "github.com/git-hulk/cula/pkg"
)

var _ cula.Session = (*session)(nil)

type session struct {
	mu        sync.Mutex
	runtime   *Runtime
	input     cula.SessionInput
	events    chan cula.Event
	sessionID string
	childCmd  *exec.Cmd
	promptCh  chan string
	doneCh    chan struct{}
	doneOnce  sync.Once
	ctx       context.Context
	cancelCtx context.CancelFunc
	parser    eventParser
}

func newSession(ctx context.Context, rt *Runtime, input cula.SessionInput) (cula.Session, error) {
	input = iruntime.NormalizeInput(input)
	runCtx, cancel := context.WithCancel(context.Background())
	s := &session{
		runtime:   rt,
		input:     input,
		events:    make(chan cula.Event, 1024),
		sessionID: input.SessionID,
		promptCh:  make(chan string, 16),
		doneCh:    make(chan struct{}),
		ctx:       runCtx,
		cancelCtx: cancel,
		parser:    eventParser{},
	}
	iruntime.Emit(s.events, s.doneCh, cula.Event{
		Type:      cula.EventState,
		Runtime:   cula.RuntimeOpenCode,
		SessionID: input.SessionID,
		State:     cula.StateRunning,
	})
	go s.consumePrompts()
	if input.Prompt != "" {
		if err := s.Send(ctx, input.Prompt); err != nil {
			_ = s.Cancel(ctx)
			return nil, err
		}
	}
	return s, nil
}

func (s *session) Send(ctx context.Context, prompt string) error {
	if prompt == "" {
		return nil
	}
	select {
	case s.promptCh <- prompt:
		return nil
	case <-s.doneCh:
		return iruntime.ErrSessionClosed
	case <-ctx.Done():
		return ctx.Err()
	}
}

func (s *session) Events() <-chan cula.Event {
	return s.events
}

func (s *session) Cancel(ctx context.Context) error {
	s.doneOnce.Do(func() {
		exit := -1
		iruntime.Emit(s.events, nil, cula.Event{
			Type:      cula.EventState,
			Runtime:   cula.RuntimeOpenCode,
			SessionID: s.sessionID,
			State:     cula.StateCanceled,
			ExitCode:  &exit,
		})
		close(s.doneCh)
		s.cancelCtx()
		s.mu.Lock()
		cmd := s.childCmd
		s.mu.Unlock()
		if cmd != nil && cmd.Process != nil {
			_ = cmd.Process.Signal(syscall.SIGTERM)
		}
		close(s.events)
	})
	return nil
}

func (s *session) consumePrompts() {
	for {
		select {
		case prompt := <-s.promptCh:
			exitCode := s.spawnAndWait(prompt)
			if exitCode != 0 {
				exit := exitCode
				iruntime.Emit(s.events, s.doneCh, cula.Event{
					Type:      cula.EventState,
					Runtime:   cula.RuntimeOpenCode,
					SessionID: s.sessionID,
					State:     cula.StateFailed,
					ExitCode:  &exit,
				})
			}
		case <-s.doneCh:
			return
		}
	}
}

func (s *session) spawnAndWait(prompt string) int {
	args := s.buildArgs(s.sessionID, prompt)
	cmd := exec.CommandContext(s.ctx, iruntime.BinaryPath(s.runtime.cfg, "opencode"), args...)
	cmd.Dir = s.input.WorkingDir
	cmd.Env = iruntime.CommandEnv(s.input, s.runtime.cfg)

	stdout, err := cmd.StdoutPipe()
	if err != nil {
		s.emitError(fmt.Sprintf("stdout pipe: %v", err))
		return 1
	}
	stderr, err := cmd.StderrPipe()
	if err != nil {
		s.emitError(fmt.Sprintf("stderr pipe: %v", err))
		return 1
	}
	if err := cmd.Start(); err != nil {
		s.emitError(fmt.Sprintf("start opencode: %v", err))
		return 1
	}

	s.mu.Lock()
	s.childCmd = cmd
	s.mu.Unlock()

	var wg sync.WaitGroup
	wg.Add(2)
	go func() {
		defer wg.Done()
		s.readStdout(stdout)
	}()
	go func() {
		defer wg.Done()
		s.readStderr(stderr)
	}()

	waitErr := cmd.Wait()
	wg.Wait()

	s.mu.Lock()
	s.childCmd = nil
	s.mu.Unlock()

	exitCode := iruntime.ExitCode(waitErr)
	if exitCode == 0 {
		iruntime.Emit(s.events, s.doneCh, cula.Event{
			Type:      cula.EventDone,
			Runtime:   cula.RuntimeOpenCode,
			SessionID: s.sessionID,
		})
	}
	return exitCode
}

func (s *session) buildArgs(sessionID, prompt string) []string {
	args := []string{"run", "--format", "json", "--thinking"}
	if s.input.Permission != cula.PermissionNever {
		args = append(args, "--dangerously-skip-permissions")
	}
	if s.input.Model != "" {
		args = append(args, "--model", s.input.Model)
	}
	if sessionID != "" {
		args = append(args, "--session", sessionID)
	}
	return append(args, prompt)
}

func (s *session) readStdout(r io.Reader) {
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 64*1024), 10*1024*1024)
	for scanner.Scan() {
		line := append([]byte(nil), scanner.Bytes()...)
		var raw json.RawMessage
		if err := json.Unmarshal(line, &raw); err != nil {
			s.emitError(fmt.Sprintf("decode stdout: %v", err))
			continue
		}
		if id := s.parser.captureSession(raw); id != "" {
			s.sessionID = id
		}
		ev, ok := ParseEvent(raw)
		if !ok {
			ev = cula.Event{Type: cula.EventRaw}
		}
		s.emitEvent(raw, ev)
	}
	if err := scanner.Err(); err != nil {
		s.emitError(fmt.Sprintf("read stdout: %v", err))
	}
}

func (s *session) readStderr(r io.Reader) {
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 64*1024), 10*1024*1024)
	for scanner.Scan() {
		iruntime.Emit(s.events, s.doneCh, cula.Event{
			Type:      cula.EventStderr,
			Runtime:   cula.RuntimeOpenCode,
			SessionID: s.sessionID,
			Error:     scanner.Text(),
		})
	}
	if err := scanner.Err(); err != nil {
		s.emitError(fmt.Sprintf("read stderr: %v", err))
	}
}

func (s *session) emitEvent(raw json.RawMessage, ev cula.Event) {
	ev.Runtime = cula.RuntimeOpenCode
	ev.SessionID = s.sessionID
	ev.Raw = raw
	iruntime.Emit(s.events, s.doneCh, ev)
}

func (s *session) emitError(message string) {
	iruntime.Emit(s.events, s.doneCh, cula.Event{
		Type:      cula.EventError,
		Runtime:   cula.RuntimeOpenCode,
		SessionID: s.sessionID,
		Error:     message,
	})
}

package tui

import "testing"

func TestRefreshTranscriptFollowsTailWhenAttached(t *testing.T) {
	m := New(Config{})
	m.phase = phaseChat
	m.width = 80
	m.height = 12
	m.layout()

	for range 20 {
		m.appendBlock(block{kind: blkInfo, title: "info", body: "line"})
	}
	m.refreshTranscript()
	if !m.viewport.AtBottom() {
		t.Fatal("expected initial transcript to follow the tail")
	}

	m.appendBlock(block{kind: blkInfo, title: "info", body: "new line"})
	m.refreshTranscript()
	if !m.viewport.AtBottom() {
		t.Fatal("expected appended content to keep following the tail")
	}
}

func TestRefreshTranscriptPreservesHistoryScroll(t *testing.T) {
	m := New(Config{})
	m.phase = phaseChat
	m.width = 80
	m.height = 12
	m.layout()

	for range 24 {
		m.appendBlock(block{kind: blkInfo, title: "info", body: "line"})
	}
	m.refreshTranscript()
	m.viewport.LineUp(3)
	m.followOutput = false
	offset := m.viewport.YOffset
	if m.viewport.AtBottom() {
		t.Fatal("expected viewport to be detached from the tail after scrolling up")
	}

	m.appendBlock(block{kind: blkInfo, title: "info", body: "new line"})
	m.refreshTranscript()
	if got := m.viewport.YOffset; got != offset {
		t.Fatalf("viewport offset = %d, want %d", got, offset)
	}
	if m.viewport.AtBottom() {
		t.Fatal("expected viewport to stay in history instead of snapping back to the tail")
	}
}

