27	func (r *Runtime) Detect(ctx context.Context) (cula.RuntimeInfo, error) {
28		binary := iruntime.BinaryPath(r.cfg, "codex")
29		info := iruntime.LookupRuntime(binary, "codex", cula.RuntimeCodex, "Codex CLI")
30		if !info.Installed {
31			return info, nil
32		}
33		if out, err := exec.CommandContext(ctx, binary, "--version").Output(); err == nil {
34			re := regexp.MustCompile(`codex-cli\s+(\S+)`)
35			if m := re.FindStringSubmatch(string(out)); len(m) > 1 {
36				info.Version = m[1]
37			}
38		}
39		home, _ := os.UserHomeDir()
40		if data, err := os.ReadFile(filepath.Join(home, ".codex", "auth.json")); err == nil {
41			var auth struct {
42				Tokens struct {
43					AccessToken string `json:"access_token"`
44				} `json:"tokens"`
45			}
46			if json.Unmarshal(data, &auth) == nil && auth.Tokens.AccessToken != "" {
47				info.AuthStatus = cula.AuthLoggedIn
48			} else {
49				info.AuthStatus = cula.AuthLoggedOut
50			}
51		} else {
52			info.AuthStatus = cula.AuthLoggedOut
53		}
54		if data, err := os.ReadFile(filepath.Join(home, ".codex", "models_cache.json")); err == nil {
55			var cache struct {
56				Models []struct {
57					Slug        string `json:"slug"`
58					DisplayName string `json:"display_name"`
59				} `json:"models"`
60			}
61			if json.Unmarshal(data, &cache) == nil {
62				for _, m := range cache.Models {
63					info.Models = append(info.Models, cula.Model{ID: m.Slug, Name: m.DisplayName})
64				}
65			}
66		}
67		return info, nil
68	}
