  1	package codex
  2	
  3	import (
  4		"encoding/json"
  5		"fmt"
  6		"strings"
  7	
  8		iruntime "github.com/git-hulk/cula/internal/runtime"
  9		cula "github.com/git-hulk/cula/pkg"
 10	)
 11	
 12	type eventParser struct{}
 13	
 14	func ParseEvent(raw json.RawMessage) (cula.Event, bool) {
 15		return eventParser{}.parse(raw)
 16	}
 17	
 18	type event struct {
 19		Method string `json:"method"`
 20		Params params `json:"params"`
 21	}
 22	
 23	type params struct {
 24		Item *item `json:"item"`
 25		Turn *turn `json:"turn"`
 26	}
 27	
 28	type turn struct {
 29		Status string `json:"status"`
 30	}
 31	
 32	type item struct {
 33		ID        string         `json:"id"`
 34		Type      string         `json:"type"`
 35		Name      string         `json:"name"`
 36		Text      string         `json:"text"`
 37		Phase     string         `json:"phase"`
 38		Command   string         `json:"command"`
 39		ExitCode  *float64       `json:"exitCode"`
 40		Arguments string         `json:"arguments"`
 41		Input     map[string]any `json:"input"`
 42		Metadata  map[string]any `json:"metadata"`
 43	}
 44	
 45	func (p eventParser) parse(raw json.RawMessage) (cula.Event, bool) {
 46		var ev event
 47		if json.Unmarshal(raw, &ev) != nil || ev.Method == "" {
 48			return cula.Event{}, false
 49		}
 50		switch ev.Method {
 51		case "turn/completed":
 52			if ev.Params.Turn == nil || ev.Params.Turn.Status == "" {
 53				return cula.Event{}, false
 54			}
 55			return cula.Event{Type: cula.EventDone}, true
 56		case "item/started":
 57			if ev.Params.Item != nil {
 58				return p.itemEvent(ev.Params.Item, false)
 59			}
 60		case "item/completed":
 61			if ev.Params.Item != nil {
 62				return p.completedItemEvent(ev.Params.Item)
 63			}
 64		}
 65		return cula.Event{}, false
 66	}
 67	
 68	func (p eventParser) completedItemEvent(item *item) (cula.Event, bool) {
 69		if item.Type == "agentMessage" && strings.TrimSpace(item.Text) != "" {
 70			// Codex tags mid-turn preamble/progress narration as "commentary"
 71			// and the terminal reply as "final_answer". Surface commentary as
 72			// an activity narration row so it groups under the assistant
 73			// banner and gets cleared at turn end alongside other progress
 74			// indicators, instead of stacking inside the final answer bubble.
 75			if item.Phase == "commentary" {
 76				return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityNarration, Parameters: []string{item.Text}}}, true
 77			}
 78			return cula.Event{Type: cula.EventText, Text: item.Text}, true
 79		}
 80		return p.itemEvent(item, true)
 81	}
 82	
 83	func (eventParser) itemEvent(item *item, completed bool) (cula.Event, bool) {
 84		switch item.Type {
 85		case "reasoning":
 86			if completed {
 87				return cula.Event{}, false
 88			}
 89			return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityThinking}}, true
 90		case "functionCall", "tool_call":
 91			input := item.Input
 92			if input == nil {
 93				input = iruntime.ParseArguments(item.Arguments)
 94			}
 95			if !completed {
 96				return cula.Event{Type: cula.EventToolCall, ToolCall: &cula.ToolCall{ID: item.ID, Name: item.Name, Input: input}}, true
 97			}
 98			return cula.Event{}, false
 99		case "commandExecution":
100			params := []string{}
101			if item.Command != "" {
102				params = append(params, iruntime.Truncate(item.Command, 160))
103			}
104			if completed && item.ExitCode != nil {
105				params = append(params, fmt.Sprintf("%d", int(*item.ExitCode)))
106			}
107			return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityCommand, Parameters: params}}, true
108		}
109		return cula.Event{}, false
110	}
