27	func (r *Runtime) Detect(ctx context.Context) (cula.RuntimeInfo, error) {
28		binary := iruntime.BinaryPath(r.cfg, "opencode")
29		info := iruntime.LookupRuntime(binary, "opencode", cula.RuntimeOpenCode, "OpenCode")
30		if !info.Installed {
31			return info, nil
32		}
33		if out, err := exec.CommandContext(ctx, binary, "--version").Output(); err == nil {
34			re := regexp.MustCompile(`(\d+\.\d+\.\d+)`)
35			if m := re.FindStringSubmatch(string(out)); len(m) > 1 {
36				info.Version = m[1]
37			}
38		}
39		home, _ := os.UserHomeDir()
40		authPath := filepath.Join(home, ".local", "share", "opencode", "auth.json")
41		if data, err := os.ReadFile(authPath); err == nil && len(data) > 2 {
42			info.AuthStatus = cula.AuthLoggedIn
43		} else {
44			info.AuthStatus = cula.AuthLoggedOut
45		}
46		if out, err := exec.CommandContext(ctx, binary, "models").Output(); err == nil {
47			for _, line := range strings.Split(string(out), "\n") {
48				id := strings.TrimSpace(line)
49				if id != "" && strings.Contains(id, "/") {
50					info.Models = append(info.Models, cula.Model{ID: id, Name: id})
51				}
52			}
53		}
54		return info, nil
55	}
56	
57	func (r *Runtime) SpawnSession(ctx context.Context, input cula.SessionInput) (cula.Session, error) {
58		return newSession(ctx, r, input)
59	}

