 11	func ParseEvent(raw json.RawMessage) (cula.Event, bool) {
 12		return eventParser{}.parse(raw)
 13	}
 14	
 15	type event struct {
 16		Type      string `json:"type"`
 17		SessionID string `json:"sessionID"`
 18		Part      *part  `json:"part"`
 19	}
 20	
 21	type part struct {
 22		ID       string         `json:"id"`
 23		Type     string         `json:"type"`
 24		Text     string         `json:"text"`
 25		Reason   string         `json:"reason"`
 26		Tool     string         `json:"tool"`
 27		CallID   string         `json:"callID"`
 28		Input    map[string]any `json:"input"`
 29		State    *state         `json:"state"`
 30		Metadata map[string]any `json:"metadata"`
 31	}
 32	
 33	type state struct {
 34		Status string         `json:"status"`
 35		Title  string         `json:"title"`
 36		Input  map[string]any `json:"input"`
 37		Output string         `json:"output"`
 38		Error  string         `json:"error"`
 39	}
 40	
 41	func (eventParser) captureSession(raw json.RawMessage) string {
 42		var ev struct {
 43			SessionID string `json:"sessionID"`
 44		}
 45		if json.Unmarshal(raw, &ev) == nil {
 46			return ev.SessionID
 47		}
 48		return ""
 49	}
 50	
 51	func (p eventParser) parse(raw json.RawMessage) (cula.Event, bool) {
 52		var ev event
 53		if json.Unmarshal(raw, &ev) != nil {
 54			return cula.Event{}, false
 55		}
 56		if ev.Type == "step_finish" {
 57			return p.stepFinishEvent(ev)
 58		}
 59		if ev.Part == nil {
 60			return cula.Event{}, false
 61		}
 62		switch ev.Part.Type {
 63		case "text":
 64			if ev.Part.Text != "" {
 65				return cula.Event{Type: cula.EventText, Text: ev.Part.Text}, true
 66			}
 67		case "reasoning":
 68			return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityThinking}}, true
 69		case "tool":
 70			return p.toolEvent(ev.Part)
 71		}
 72		return cula.Event{}, false
 73	}
 74	
 75	func (eventParser) stepFinishEvent(ev event) (cula.Event, bool) {
 76		if ev.Part == nil {
 77			return cula.Event{Type: cula.EventDone}, true
 78		}
 79		switch ev.Part.Reason {
 80		case "", "stop", "length", "error":
 81			return cula.Event{Type: cula.EventDone}, true
 82		default:
 83			return cula.Event{}, false
 84		}
 85	}
 86	
 87	func (eventParser) toolEvent(part *part) (cula.Event, bool) {
 88		toolName := part.Tool
 89		if toolName == "" && part.State != nil {
 90			toolName = part.State.Title
 91		}
 92		input := part.Input
 93		if input == nil && part.State != nil {
 94			input = part.State.Input
 95		}
 96		if part.State != nil && (part.State.Status == "completed" || part.State.Status == "error") {
 97			content := part.State.Output
 98			if content == "" {
 99				content = part.State.Error
100			}
101			if content != "" {
102				return cula.Event{Type: cula.EventToolResult, ToolResult: &cula.ToolResult{ToolCallID: part.CallID, Content: content}}, true
103			}
104		}
105		return cula.Event{Type: cula.EventToolCall, ToolCall: &cula.ToolCall{ID: part.CallID, Name: toolName, Input: input}}, true
106	}
