  1	package claudecode
  2	
  3	import (
  4		"encoding/json"
  5		"strings"
  6	
  7		iruntime "github.com/git-hulk/cula/internal/runtime"
  8		cula "github.com/git-hulk/cula/pkg"
  9	)
 10	
 11	type eventParser struct{}
 12	
 13	func ParseEvent(raw json.RawMessage) (cula.Event, bool) {
 14		return eventParser{}.parse(raw)
 15	}
 16	
 17	type event struct {
 18		Type      string            `json:"type"`
 19		SubType   string            `json:"subtype"`
 20		Role      string            `json:"role"`
 21		SessionID string            `json:"session_id"`
 22		Message   *message          `json:"message"`
 23		Content   iruntime.RawValue `json:"content"`
 24	}
 25	
 26	type message struct {
 27		Content []block `json:"content"`
 28	}
 29	
 30	type block struct {
 31		Type      string            `json:"type"`
 32		ID        string            `json:"id"`
 33		Name      string            `json:"name"`
 34		Text      string            `json:"text"`
 35		Input     map[string]any    `json:"input"`
 36		ToolUseID string            `json:"tool_use_id"`
 37		Content   iruntime.RawValue `json:"content"`
 38	}
 39	
 40	func (eventParser) captureSession(raw json.RawMessage) string {
 41		var ev struct {
 42			Type      string `json:"type"`
 43			SubType   string `json:"subtype"`
 44			SessionID string `json:"session_id"`
 45		}
 46		if json.Unmarshal(raw, &ev) == nil && ev.SessionID != "" &&
 47			(ev.Type == "init" || (ev.Type == "system" && ev.SubType == "init")) {
 48			return ev.SessionID
 49		}
 50		return ""
 51	}
 52	
 53	func (p eventParser) parse(raw json.RawMessage) (cula.Event, bool) {
 54		var ev event
 55		if json.Unmarshal(raw, &ev) != nil {
 56			return cula.Event{}, false
 57		}
 58		switch ev.Type {
 59		case "result":
 60			return cula.Event{Type: cula.EventDone}, true
 61		case "assistant":
 62			if out, ok := p.assistantEvent(ev); ok {
 63				return out, true
 64			}
 65		case "user":
 66			if out, ok := p.toolResultEvent(ev); ok {
 67				return out, true
 68			}
 69		}
 70		if ev.Role == "assistant" {
 71			if text, ok := ev.Content.AsString(); ok && strings.TrimSpace(text) != "" {
 72				return cula.Event{Type: cula.EventText, Text: text}, true
 73			}
 74		}
 75		for _, b := range contentBlocks(ev.Content) {
 76			if out, ok := toolResultBlockEvent(b); ok {
 77				return out, true
 78			}
 79		}
 80		return cula.Event{}, false
 81	}
 82	
 83	func (eventParser) assistantEvent(ev event) (cula.Event, bool) {
 84		if ev.Message == nil {
 85			return cula.Event{}, false
 86		}
 87		for _, b := range ev.Message.Content {
 88			switch b.Type {
 89			case "thinking":
 90				return cula.Event{Type: cula.EventActivity, Activity: &cula.Activity{Type: cula.ActivityThinking}}, true
 91			case "tool_use":
 92				return cula.Event{Type: cula.EventToolCall, ToolCall: &cula.ToolCall{ID: b.ID, Name: b.Name, Input: b.Input}}, true
 93			}
 94		}
 95		for _, b := range ev.Message.Content {
 96			if b.Type == "text" && strings.TrimSpace(b.Text) != "" {
 97				return cula.Event{Type: cula.EventText, Text: b.Text}, true
 98			}
 99		}
100		return cula.Event{}, false
101	}
102	
103	func (eventParser) toolResultEvent(ev event) (cula.Event, bool) {
104		if ev.Message == nil {
105			return cula.Event{}, false
106		}
107		for _, b := range ev.Message.Content {
108			if out, ok := toolResultBlockEvent(b); ok {
109				return out, true
110			}
111		}
112		return cula.Event{}, false
113	}
114	
115	func toolResultBlockEvent(b block) (cula.Event, bool) {
116		if b.Type != "tool_result" || b.ToolUseID == "" {
117			return cula.Event{}, false
118		}
119		text := b.Content.AsText()
120		if text == "" {
121			return cula.Event{}, false
122		}
123		return cula.Event{Type: cula.EventToolResult, ToolResult: &cula.ToolResult{ToolCallID: b.ToolUseID, Content: text}}, true
124	}
125	
126	func contentBlocks(content iruntime.RawValue) []block {
127		if raw := content.Raw(); len(raw) == 0 || raw[0] != '[' {
128			return nil
129		}
130		var blocks []block
131		_ = json.Unmarshal(content.Raw(), &blocks)
132		return blocks
133	}
